def _goodwe_ems_prefix_candidates(hass: HomeAssistant) -> list[str]:
    """Return GoodWe EMS prefixes with both required HA entities loaded."""
    try:
        mode_entity_ids = hass.states.async_entity_ids("select")
    except TypeError:
        mode_entity_ids = [
            entity_id
            for entity_id in hass.states.async_entity_ids()
            if entity_id.startswith("select.")
        ]

    candidates: list[str] = []
    for entity_id in mode_entity_ids:
        if not entity_id.startswith("select.") or not entity_id.endswith("_ems_mode"):
            continue
        prefix = entity_id.removeprefix("select.").removesuffix("_ems_mode")
        if hass.states.get(f"number.{prefix}_ems_power_limit") is not None:
            candidates.append(prefix)

    return sorted(set(candidates))


def _resolve_goodwe_ems_entity_prefix(hass: HomeAssistant, prefix: str | None) -> str:
    """Resolve a configured GoodWe EMS prefix from the loaded HA entity pair."""
    typed_prefix = (prefix or "").strip()
    if (
        typed_prefix
        and hass.states.get(f"select.{typed_prefix}_ems_mode") is not None
        and hass.states.get(f"number.{typed_prefix}_ems_power_limit") is not None
    ):
        return typed_prefix

    candidates = _goodwe_ems_prefix_candidates(hass)
    if typed_prefix in candidates:
        return typed_prefix
    if "goodwe" in candidates:
        return "goodwe"
    if len(candidates) == 1:
        return candidates[0]

    return typed_prefix


async def _resolve_goodwe_entity_telemetry_prefix(
    hass: HomeAssistant,
    prefix: str | None,
) -> str:
    """Return a validated GoodWe entity telemetry prefix, or empty string."""
    from .inverters.goodwe_entity import GoodWeEntityTelemetryController

    controller = GoodWeEntityTelemetryController(hass, entity_prefix=prefix or "")
    try:
        await controller.connect()
        return controller.entity_prefix
    except Exception as err:
        _LOGGER.debug("GoodWe entity telemetry not available: %s", err)
        return ""


async def fetch_active_amber_site_id(hass: HomeAssistant, api_token: str) -> str | None:
    """
    Fetch the active Amber site ID from the API.

    Returns the first active site ID, or None if no sites found.
    This ensures we always use the current active site, not a stale/closed one.
    """
    try:
        session = async_get_clientsession(hass)
        headers = {"Authorization": f"Bearer {api_token}"}

        async with session.get(
            f"{AMBER_API_BASE_URL}/sites",
            headers=headers,
            timeout=aiohttp.ClientTimeout(total=30)
        ) as response:
            if response.status == 200:
                sites = await response.json()
                if sites and len(sites) > 0:
                    # Filter for active sites (status == "active")
                    active_sites = [s for s in sites if s.get("status") == "active"]
                    if active_sites:
                        site_id = active_sites[0]["id"]
                        _LOGGER.info(f"🔍 Fetched active Amber site ID from API: {site_id}")
                        return site_id
                    # If no active sites, fall back to first site
                    site_id = sites[0]["id"]
                    _LOGGER.warning(f"No active Amber sites found, using first available: {site_id}")
                    return site_id
                _LOGGER.error("No Amber sites found in API response")
                return None
            else:
                _LOGGER.error(f"Failed to fetch Amber sites: HTTP {response.status}")
                return None
    except Exception as e:
        _LOGGER.error(f"Error fetching Amber site ID: {e}")
        return None


class SyncCoordinator:
    """
    Coordinates Tesla sync with smarter price-aware logic (async version for Home Assistant).

    Sync flow for each 5-minute period:
    1. At 0s: Sync immediately using forecast price (get price to Tesla ASAP)
    2. When WebSocket arrives: Re-sync only if price differs from forecast
    3. At 35s: If no WebSocket yet, check REST API and sync if price differs
    4. At 60s: Final REST API check if price still hasn't been confirmed

    This ensures:
    - Fast response: Price synced at start of period using forecast
    - Accuracy: Re-sync when actual price differs from forecast
    - Reliability: Multiple fallback checks if WebSocket fails
    """

    def __init__(self):
        self._websocket_event = asyncio.Event()
        self._websocket_data = None
        self._current_period = None  # Track which 5-min period we're in
        self._lock = asyncio.Lock()
        self._initial_sync_done = False  # Has initial forecast sync happened this period?
        self._websocket_received = False  # Has WebSocket delivered this period?

    def _get_current_period(self):
        """Get the current 5-minute period timestamp."""
        now = dt_util.utcnow()
        current_period = now.replace(second=0, microsecond=0)
        return current_period.replace(minute=current_period.minute - (current_period.minute % 5))

    async def _reset_if_new_period(self):
        """Reset state if we've moved to a new 5-minute period."""
        current_period = self._get_current_period()
        if self._current_period != current_period:
            _LOGGER.info(f"🆕 New sync period: {current_period}")
            self._current_period = current_period
            self._initial_sync_done = False
            self._websocket_received = False
            self._websocket_event.clear()
            self._websocket_data = None
            return True
        return False

    def notify_websocket_update(self, prices_data):
        """Called by WebSocket when new price data arrives."""
        self._websocket_data = prices_data
        self._websocket_received = True
        self._websocket_event.set()
        _LOGGER.info("📡 WebSocket price update received, notifying sync coordinator")

    def get_websocket_data(self):
        """Get the current WebSocket data if available."""
        return self._websocket_data

    async def mark_initial_sync_done(self):
        """Mark that the initial forecast sync has been completed for this period."""
        async with self._lock:
            await self._reset_if_new_period()
            self._initial_sync_done = True
            _LOGGER.info("✅ Initial forecast sync marked as done for this period")

    async def should_do_initial_sync(self):
        """
        Check if we should do the initial forecast sync at start of period.

        Returns:
            bool: True if initial sync hasn't been done yet this period
        """
        async with self._lock:
            await self._reset_if_new_period()
            if self._initial_sync_done:
                _LOGGER.debug("⏭️  Initial sync already done this period")
                return False
            return True

    async def has_websocket_delivered(self):
        """Check if WebSocket has delivered price data this period."""
        async with self._lock:
            await self._reset_if_new_period()
            return self._websocket_received

    # Legacy methods for backwards compatibility
    async def wait_for_websocket_or_timeout(self, timeout_seconds=15):
        """Wait for WebSocket data or timeout (legacy method)."""
        _LOGGER.info(f"⏱️  Waiting up to {timeout_seconds}s for WebSocket price update...")

        try:
            await asyncio.wait_for(self._websocket_event.wait(), timeout=timeout_seconds)

            async with self._lock:
                if self._websocket_data:
                    _LOGGER.info("✅ WebSocket data received, using real-time prices")
                    return self._websocket_data
                else:
                    _LOGGER.warning("⏰ WebSocket event set but no data available")
                    return None

        except asyncio.TimeoutError:
            _LOGGER.info(f"⏰ WebSocket timeout after {timeout_seconds}s, falling back to REST API")
            return None

    async def already_synced_this_period(self):
        """Legacy method - check if initial sync is done."""
        async with self._lock:
            await self._reset_if_new_period()
            return self._initial_sync_done

    async def should_sync_this_period(self):
        """Legacy method - now always returns True for initial sync check."""
        async with self._lock:
            await self._reset_if_new_period()
            return not self._initial_sync_done


class AEMOSpikeManager:
    """
    Manages AEMO price spike detection and Tesla tariff modifications.

    When a price spike is detected:
    1. Save the current Tesla tariff
    2. Switch to autonomous mode
    3. Upload a spike tariff optimized for export
    4. Wait for price to normalize
    5. Restore the saved tariff and operation mode
    """

    def __init__(
        self,
        hass: HomeAssistant,
        entry: ConfigEntry,
        region: str,
        threshold: float,
        site_id: str,
        api_token: str,
        api_provider: str = TESLA_PROVIDER_TESLEMETRY,
        token_getter: callable = None,
    ):
        """Initialize the AEMO spike manager."""
        self.hass = hass
        self.entry = entry
        self.region = region
        self.threshold = threshold
        self.site_id = site_id
        self._api_token = api_token  # Fallback token
        self._token_getter = token_getter  # Callable to get fresh token
        self.api_provider = api_provider

        # State tracking
        self._in_spike_mode = False
        self._spike_start_time: datetime | None = None
        self._saved_tariff: dict | None = None
        self._saved_operation_mode: str | None = None
        self._last_price: float | None = None
        self._last_check: datetime | None = None

        # Create AEMO client (uses NEMWEB dispatch ZIP with JSON fallback)
        from .aemo_api import AEMOAPIClient
        session = async_get_clientsession(hass)
        self._aemo_client = AEMOAPIClient(session)

        _LOGGER.info(
            "AEMO Spike Manager initialized: region=%s, threshold=$%.0f/MWh",
            region,
            threshold,
        )

    def _get_current_token(self) -> tuple[str | None, str]:
        """Get the current API token, fetching fresh if token_getter is available.

        Returns None as the token if token_getter is set but returned no token —
        callers should treat this as a transient failure rather than using the
        potentially stale startup token.
        """
        if self._token_getter:
            try:
                token, provider = self._token_getter()
                if token:
                    self.api_provider = provider
                    return token, provider
                _LOGGER.warning("Token getter returned no token (fleet integration may be refreshing)")
                return None, self.api_provider
            except Exception as e:
                _LOGGER.warning("Token getter failed: %s", e)
                return None, self.api_provider
        return self._api_token, self.api_provider

    @property
    def in_spike_mode(self) -> bool:
        """Return whether currently in spike mode."""
        return self._in_spike_mode

    @property
    def last_price(self) -> float | None:
        """Return the last observed AEMO price."""
        return self._last_price

    @property
    def spike_start_time(self) -> datetime | None:
        """Return when the current spike started."""
        return self._spike_start_time

    async def check_and_handle_spike(self) -> None:
        """Check AEMO prices and handle spike mode transitions."""

        self._last_check = dt_util.utcnow()

        # Check for spike
        is_spike, current_price, price_data = await self._aemo_client.check_price_spike(
            self.region, self.threshold
        )

        if current_price is not None:
            self._last_price = current_price

        if current_price is None:
            _LOGGER.warning("Could not fetch AEMO price - skipping spike check")
            return

        # SPIKE DETECTED - Enter spike mode
        if is_spike and not self._in_spike_mode:
            await self._enter_spike_mode(current_price)

        # NO SPIKE - Exit spike mode if currently in it
        elif not is_spike and self._in_spike_mode:
            await self._exit_spike_mode(current_price)

        # Still in spike mode - maybe update tariff if price changed significantly
        elif is_spike and self._in_spike_mode:
            _LOGGER.debug(
                "Still in spike mode: $%.2f/MWh (threshold: $%.0f/MWh)",
                current_price,
                self.threshold,
            )

    async def _enter_spike_mode(self, current_price: float) -> None:
        """Enter spike mode: save tariff, switch to autonomous, upload spike tariff."""

        _LOGGER.warning(
            "SPIKE DETECTED: $%.2f/MWh >= $%.0f/MWh threshold - entering spike mode",
            current_price,
            self.threshold,
        )

        try:
            # Get fresh token in case it was refreshed by tesla_fleet integration
            current_token, current_provider = self._get_current_token()
            if not current_token:
                _LOGGER.warning("Cannot enter spike mode — token temporarily unavailable")
                return
            session = async_get_clientsession(self.hass)
            headers = {
                "Authorization": f"Bearer {current_token}",
                "Content-Type": "application/json",
            }
            api_base = get_tesla_api_base_url(current_provider, self.entry.data.get(CONF_FLEET_API_BASE_URL))

            # Step 1: Save current tariff
            _LOGGER.info("Saving current tariff before spike mode...")
            async with session.get(
                f"{api_base}/api/1/energy_sites/{self.site_id}/tariff_rate",
                headers=headers,
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status == 200:
                    data = await response.json()
                    resp = data.get("response", {})
                    # Try tariff_content_v2 first, then fall back to tariff_content
                    tariff_candidate = resp.get("tariff_content_v2") or resp.get("tariff_content")
                    self._saved_tariff = _select_restorable_tesla_tariff(tariff_candidate)
                    if self._saved_tariff:
                        _LOGGER.info("Saved current tariff for restoration after spike (name: %s)",
                                    self._saved_tariff.get("name", "unknown"))
                    elif tariff_candidate:
                        _LOGGER.warning(
                            "Ignoring PowerSync force tariff from tariff_rate as spike restore baseline (name: %s)",
                            _tariff_display_name(tariff_candidate),
                        )
                    else:
                        _LOGGER.warning("Could not extract tariff from tariff_rate response - will try site_info")
                else:
                    _LOGGER.warning("tariff_rate endpoint returned %s - will try site_info fallback", response.status)

            # Step 2: Get and save current operation mode (and tariff fallback)
            async with session.get(
                f"{api_base}/api/1/energy_sites/{self.site_id}/site_info",
                headers=headers,
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status == 200:
                    data = await response.json()
                    site_info = data.get("response", {})
                    self._saved_operation_mode = site_info.get("default_real_mode")
                    _LOGGER.info("Saved operation mode: %s", self._saved_operation_mode)

                    # Fallback: if tariff wasn't saved from tariff_rate, try to get it from site_info
                    if not self._saved_tariff:
                        site_tariff = site_info.get("tariff_content_v2") or site_info.get("tariff_content")
                        self._saved_tariff = _select_restorable_tesla_tariff(site_tariff)
                        if self._saved_tariff:
                            _LOGGER.info("Saved tariff from site_info fallback (name: %s)",
                                        self._saved_tariff.get("name", "unknown"))
                        elif site_tariff:
                            _LOGGER.warning(
                                "Ignoring PowerSync force tariff from site_info as spike restore baseline (name: %s)",
                                _tariff_display_name(site_tariff),
                            )
                        else:
                            _LOGGER.warning("No tariff found in site_info either - restore may not work")

            # Step 3: Switch to autonomous mode for best export behavior
            if self._saved_operation_mode != "autonomous":
                _LOGGER.info("Switching to autonomous mode for optimal export...")
                async with session.post(
                    f"{api_base}/api/1/energy_sites/{self.site_id}/operation",
                    headers=headers,
                    json={"default_real_mode": "autonomous"},
                    timeout=aiohttp.ClientTimeout(total=30),
                ) as response:
                    if response.status == 200:
                        _LOGGER.info("Switched to autonomous mode")
                    else:
                        _LOGGER.warning("Could not switch operation mode: %s", response.status)

            # Step 4: Create and upload spike tariff
            spike_tariff = self._create_spike_tariff(current_price)
            success = await send_tariff_to_tesla(
                self.hass,
                self.site_id,
                spike_tariff,
                current_token,
                current_provider,
                fleet_base_url=self.entry.data.get(CONF_FLEET_API_BASE_URL),
            )

            if success:
                self._in_spike_mode = True
                self._spike_start_time = dt_util.utcnow()
                _LOGGER.warning(
                    "SPIKE MODE ACTIVE: Tariff uploaded to maximize export at $%.2f/MWh",
                    current_price,
                )
            else:
                _LOGGER.error("Failed to upload spike tariff")

        except Exception as e:
            _LOGGER.error("Error entering spike mode: %s", e, exc_info=True)

    async def _exit_spike_mode(self, current_price: float) -> None:
        """Exit spike mode: restore saved tariff and operation mode."""
        _LOGGER.info(
            "Price normalized: $%.2f/MWh < $%.0f/MWh threshold - exiting spike mode",
            current_price,
            self.threshold,
        )

        try:
            # Get fresh token in case it was refreshed by tesla_fleet integration
            current_token, current_provider = self._get_current_token()
            if not current_token:
                _LOGGER.warning("Cannot exit spike mode — token temporarily unavailable")
                return
            session = async_get_clientsession(self.hass)
            headers = {
                "Authorization": f"Bearer {current_token}",
                "Content-Type": "application/json",
            }
            api_base = get_tesla_api_base_url(current_provider, self.entry.data.get(CONF_FLEET_API_BASE_URL))

            # Step 1: Switch to self_consumption mode first (helps tariff apply)
            _LOGGER.info("Switching to self_consumption mode before tariff restore...")
            async with session.post(
                f"{api_base}/api/1/energy_sites/{self.site_id}/operation",
                headers=headers,
                json={"default_real_mode": "self_consumption"},
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status == 200:
                    _LOGGER.info("Switched to self_consumption mode")

            # Step 2: Restore saved tariff
            restore_tariff = _select_restorable_tesla_tariff(self._saved_tariff)
            if restore_tariff:
                _LOGGER.info("Restoring saved tariff...")
                success = await send_tariff_to_tesla(
                    self.hass,
                    self.site_id,
                    restore_tariff,
                    current_token,
                    current_provider,
                    fleet_base_url=self.entry.data.get(CONF_FLEET_API_BASE_URL),
                )
                if success:
                    _LOGGER.info("Restored saved tariff successfully")
                else:
                    _LOGGER.error("Failed to restore saved tariff")
            elif self._saved_tariff:
                _LOGGER.warning(
                    "Skipping restore of PowerSync force tariff after spike mode (name: %s)",
                    _tariff_display_name(self._saved_tariff),
                )
            else:
                _LOGGER.warning("No saved tariff to restore")

            # Step 3: Wait for Tesla to process the tariff
            await asyncio.sleep(5)

            # Step 4: Restore original operation mode
            restore_mode = self._saved_operation_mode or "autonomous"
            _LOGGER.info("Restoring operation mode to: %s", restore_mode)
            async with session.post(
                f"{api_base}/api/1/energy_sites/{self.site_id}/operation",
                headers=headers,
                json={"default_real_mode": restore_mode},
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status == 200:
                    _LOGGER.info("Restored operation mode to %s", restore_mode)

            # Clear spike state
            self._in_spike_mode = False
            self._spike_start_time = None
            _LOGGER.info("SPIKE MODE ENDED: Normal operation restored")

        except Exception as e:
            _LOGGER.error("Error exiting spike mode: %s", e, exc_info=True)

    def _create_spike_tariff(self, current_aemo_price_mwh: float) -> dict:
        """
        Create a Tesla tariff optimized for exporting during price spikes.

        Uses very high sell rates to encourage Powerwall to export all energy.
        """

        # Convert $/MWh to $/kWh (divide by 1000) and apply 3x markup
        # This creates a HUGE sell incentive that Powerwall will respond to
        sell_rate_spike = (current_aemo_price_mwh / 1000.0) * 3.0

        # Buy rate must EXCEED sell rate to prevent grid charging arbitrage.
        # If buy < sell, Powerwall sees profit in charging from grid to re-sell,
        # which is the opposite of what we want during a spike.
        buy_rate = max(sell_rate_spike * 2.0, 5.0)  # Always >> sell rate
        sell_rate_normal = 0.08  # 8c/kWh normal feed-in

        # Get current 30-minute period
        now = dt_util.now()
        current_period_index = (now.hour * 2) + (1 if now.minute >= 30 else 0)

        # Create rate periods - spike for next 2 hours (4 periods)
        buy_rates = []
        sell_rates = []
        spike_window_periods = 4

        for i in range(48):
            buy_rates.append(buy_rate)

            # Apply spike sell rate for current period + next few periods
            periods_from_now = (i - current_period_index) % 48
            if periods_from_now < spike_window_periods:
                sell_rates.append(sell_rate_spike)
            else:
                sell_rates.append(sell_rate_normal)

        tariff = {
            "code": "AEMO-SPIKE",
            "utility": "AEMO Spike Response",
            "name": f"Spike Tariff (${current_aemo_price_mwh:.0f}/MWh)",
            "daily_charges": [{"name": "Grid Connection", "amount": 1.0}],
            "demand_charges": {
                "ALL": {"ALL": 0}
            },
            "energy_charges": {
                "ALL": {
                    "ALL": 0
                }
            },
            "seasons": {
                "Summer": {
                    "fromMonth": 1,
                    "fromDay": 1,
                    "toMonth": 12,
                    "toDay": 31,
                    "tou_periods": {
                        "SPIKE": {
                            "periods": [{"fromDayOfWeek": 0, "toDayOfWeek": 6, "fromHour": 0, "fromMinute": 0, "toHour": 0, "toMinute": 0}],
                            "buy": buy_rate,
                            "sell": sell_rate_spike,
                        }
                    }
                }
            },
            "sell_tariff": {
                "name": "Spike Export",
                "utility": "AEMO",
                "daily_charges": [],
                "demand_charges": {},
                "energy_charges": {
                    "ALL": {"ALL": sell_rate_spike}
                }
            }
        }

        _LOGGER.info(
            "Created spike tariff: buy=$%.2f/kWh, sell=$%.2f/kWh (AEMO price: $%.0f/MWh)",
            buy_rate,
            sell_rate_spike,
            current_aemo_price_mwh,
        )

        return tariff

    def get_status(self) -> dict:
        """Get current spike manager status."""
        return {
            "enabled": True,
            "region": self.region,
            "threshold": self.threshold,
            "in_spike_mode": self._in_spike_mode,
            "last_price": self._last_price,
            "spike_start_time": self._spike_start_time.isoformat() if self._spike_start_time else None,
            "last_check": self._last_check.isoformat() if self._last_check else None,
        }


class GenericAEMOSpikeManager:
    """
    Battery-agnostic AEMO price spike detection manager.

    Monitors AEMO prices and triggers force discharge via HA service calls
    (power_sync.force_discharge / power_sync.restore_normal) which handle
    all battery systems internally (Sigenergy, Sungrow, FoxESS).

    Tesla uses its own AEMOSpikeManager with tariff-based control.

    When a price spike is detected:
    1. Force discharge the battery via service call
    2. Send push notification to user
    3. Wait for price to normalize
    4. Restore normal operation via service call
    5. Send notification that spike ended
    """

    def __init__(
        self,
        hass: HomeAssistant,
        entry: ConfigEntry,
        region: str,
        threshold: float,
        battery_type: str,
    ):
        """Initialize the generic AEMO spike manager.

        Args:
            hass: HomeAssistant instance
            entry: Config entry
            region: AEMO NEM region code (NSW1, QLD1, VIC1, SA1, TAS1)
            threshold: Price threshold in $/MWh to trigger spike mode
            battery_type: Battery system type for logging (sigenergy, sungrow, foxess)
        """
        self.hass = hass
        self.entry = entry
        self.region = region
        self.threshold = threshold
        self._battery_type = battery_type

        # State tracking
        self._in_spike_mode = False
        self._spike_start_time: datetime | None = None
        self._last_price: float | None = None
        self._last_check: datetime | None = None

        # Create AEMO client (uses NEMWEB dispatch ZIP with JSON fallback)
        from .aemo_api import AEMOAPIClient
        session = async_get_clientsession(hass)
        self._aemo_client = AEMOAPIClient(session)

        _LOGGER.info(
            "Generic AEMO Spike Manager initialized: battery=%s, region=%s, threshold=$%.0f/MWh",
            battery_type,
            region,
            self.threshold,
        )

    @property
    def in_spike_mode(self) -> bool:
        """Return whether currently in spike mode."""
        return self._in_spike_mode

    @property
    def last_price(self) -> float | None:
        """Return the last observed AEMO price."""
        return self._last_price

    @property
    def spike_start_time(self) -> datetime | None:
        """Return when the current spike started."""
        return self._spike_start_time

    async def check_and_handle_spike(self) -> None:
        """Check AEMO prices and handle spike mode transitions."""

        self._last_check = dt_util.utcnow()

        # Check for spike
        is_spike, current_price, price_data = await self._aemo_client.check_price_spike(
            self.region, self.threshold
        )

        if current_price is not None:
            self._last_price = current_price

        if current_price is None:
            _LOGGER.warning("%s: Could not fetch AEMO price - skipping spike check", self._battery_type)
            return

        # SPIKE DETECTED - Enter spike mode
        if is_spike and not self._in_spike_mode:
            await self._enter_spike_mode(current_price)

        # NO SPIKE - Exit spike mode if currently in it
        elif not is_spike and self._in_spike_mode:
            await self._exit_spike_mode(current_price)

        # Still in spike mode - log status
        elif is_spike and self._in_spike_mode:
            _LOGGER.debug(
                "%s: Still in spike mode: $%.2f/MWh (threshold: $%.0f/MWh)",
                self._battery_type,
                current_price,
                self.threshold,
            )

    async def _enter_spike_mode(self, current_price: float) -> None:
        """Enter spike mode: force discharge via service call and notify user."""

        _LOGGER.warning(
            "%s SPIKE DETECTED: $%.2f/MWh >= $%.0f/MWh threshold - starting force discharge",
            self._battery_type,
            current_price,
            self.threshold,
        )

        try:
            # Force discharge via battery-agnostic service call
            await self.hass.services.async_call(
                DOMAIN, SERVICE_FORCE_DISCHARGE, {}, blocking=True
            )

            self._in_spike_mode = True
            self._spike_start_time = dt_util.utcnow()
            _LOGGER.warning(
                "%s SPIKE MODE ACTIVE: Battery force discharging at $%.2f/MWh",
                self._battery_type,
                current_price,
            )

            # Send push notification
            try:
                from .automations.actions import _send_expo_push
                await _send_expo_push(
                    self.hass,
                    "Price Spike",
                    f"${current_price:.0f}/MWh - discharging battery",
                )
            except Exception as notify_err:
                _LOGGER.debug("Could not send spike start notification: %s", notify_err)

        except Exception as e:
            _LOGGER.error("%s: Error entering spike mode: %s", self._battery_type, e, exc_info=True)

    async def _exit_spike_mode(self, current_price: float) -> None:
        """Exit spike mode: restore normal operation via service call and notify user."""

        _LOGGER.info(
            "%s: Price normalized: $%.2f/MWh < $%.0f/MWh threshold - restoring normal operation",
            self._battery_type,
            current_price,
            self.threshold,
        )

        try:
            # Calculate spike duration for notification
            spike_duration_minutes = 0
            if self._spike_start_time:
                spike_duration = dt_util.utcnow() - self._spike_start_time
                spike_duration_minutes = int(spike_duration.total_seconds() / 60)

            # Restore normal operation via battery-agnostic service call
            await self.hass.services.async_call(
                DOMAIN, SERVICE_RESTORE_NORMAL, {}, blocking=True
            )

            _LOGGER.info("%s: Normal operation restored after spike", self._battery_type)

            # Send push notification
            try:
                from .automations.actions import _send_expo_push
                await _send_expo_push(
                    self.hass,
                    "Price Normal",
                    f"${current_price:.0f}/MWh - spike ended ({spike_duration_minutes}min)",
                )
            except Exception as notify_err:
                _LOGGER.debug("Could not send spike end notification: %s", notify_err)

            # Clear spike state
            self._in_spike_mode = False
            self._spike_start_time = None

        except Exception as e:
            _LOGGER.error("%s: Error exiting spike mode: %s", self._battery_type, e, exc_info=True)
            # Still clear state on error to avoid getting stuck
            self._in_spike_mode = False
            self._spike_start_time = None

    def get_status(self) -> dict:
        """Get current spike manager status."""
        return {
            "enabled": True,
            "region": self.region,
            "threshold": self.threshold,
            "in_spike_mode": self._in_spike_mode,
            "last_price": self._last_price,
            "spike_start_time": self._spike_start_time.isoformat() if self._spike_start_time else None,
            "last_check": self._last_check.isoformat() if self._last_check else None,
            "battery_system": self._battery_type,
        }


class SavingSessionTariffManager:
    """Manages Tesla tariff modifications for Octopus Saving Sessions.

    When a joined session starts:
    1. Save current Tesla tariff and operation mode
    2. Upload session tariff with massive sell rates
    3. Switch to autonomous mode for optimal export
    When session ends:
    4. Restore saved tariff and operation mode

    Modelled on AEMOSpikeManager.
    """

    def __init__(
        self,
        hass: HomeAssistant,
        entry: ConfigEntry,
        session_coordinator,
        site_id: str,
        api_token: str,
        api_provider: str = TESLA_PROVIDER_TESLEMETRY,
        token_getter: callable = None,
        octopoints_per_penny: int = 8,
    ):
        """Initialize the saving session tariff manager."""
        self.hass = hass
        self.entry = entry
        self._session_coordinator = session_coordinator
        self.site_id = site_id
        self._api_token = api_token
        self._token_getter = token_getter
        self.api_provider = api_provider
        self._octopoints_per_penny = octopoints_per_penny

        # State tracking
        self._in_session_mode = False
        self._session_start_time: datetime | None = None
        self._saved_tariff: dict | None = None
        self._saved_operation_mode: str | None = None
        self._active_session_code: str | None = None

        _LOGGER.info("Saving Session Tariff Manager initialized for Tesla site %s", site_id)

    def _get_current_token(self) -> tuple[str | None, str]:
        """Get the current API token."""
        if self._token_getter:
            try:
                token, provider = self._token_getter()
                if token:
                    self.api_provider = provider
                    return token, provider
                _LOGGER.warning("Token getter returned no token (fleet integration may be refreshing)")
                return None, self.api_provider
            except Exception as e:
                _LOGGER.warning("Token getter failed: %s", e)
                return None, self.api_provider
        return self._api_token, self.api_provider

    @property
    def in_session_mode(self) -> bool:
        """Return whether currently in session mode."""
        return self._in_session_mode

    async def check_and_handle_sessions(self) -> None:
        """Check if a saving session is active and manage tariff."""
        if not self._session_coordinator or not self._session_coordinator.data:
            return

        sessions = self._session_coordinator.data.get("sessions", [])
        active = next(
            (s for s in sessions if s.is_active() and s.joined and s.session_type == "saving"),
            None,
        )

        if active and not self._in_session_mode:
            await self._enter_session_mode(active)
        elif not active and self._in_session_mode:
            await self._exit_session_mode()

    async def _enter_session_mode(self, session) -> None:
        """Save tariff, create session tariff, upload to Tesla."""

        _LOGGER.warning(
            "SAVING SESSION STARTING: %s (%s - %s, %d octopoints/kWh) - entering session mode",
            session.code, session.start, session.end, session.octopoints_per_kwh,
        )

        try:
            current_token, current_provider = self._get_current_token()
            if not current_token:
                _LOGGER.warning("Cannot enter session mode — token temporarily unavailable")
                return
            session_http = async_get_clientsession(self.hass)
            headers = {
                "Authorization": f"Bearer {current_token}",
                "Content-Type": "application/json",
            }
            api_base = get_tesla_api_base_url(current_provider, self.entry.data.get(CONF_FLEET_API_BASE_URL))

            # Step 1: Save current tariff
            _LOGGER.info("Saving current tariff before session mode...")
            async with session_http.get(
                f"{api_base}/api/1/energy_sites/{self.site_id}/tariff_rate",
                headers=headers,
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status == 200:
                    data = await response.json()
                    resp = data.get("response", {})
                    tariff_candidate = resp.get("tariff_content_v2") or resp.get("tariff_content")
                    self._saved_tariff = _select_restorable_tesla_tariff(tariff_candidate)
                    if self._saved_tariff:
                        _LOGGER.info("Saved current tariff (name: %s)", self._saved_tariff.get("name", "unknown"))
                    elif tariff_candidate:
                        _LOGGER.warning(
                            "Ignoring PowerSync force tariff from tariff_rate as session restore baseline (name: %s)",
                            _tariff_display_name(tariff_candidate),
                        )
                    else:
                        _LOGGER.warning("Could not extract tariff from tariff_rate response")

            # Step 2: Get and save current operation mode
            async with session_http.get(
                f"{api_base}/api/1/energy_sites/{self.site_id}/site_info",
                headers=headers,
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status == 200:
                    data = await response.json()
                    site_info = data.get("response", {})
                    self._saved_operation_mode = site_info.get("default_real_mode")
                    _LOGGER.info("Saved operation mode: %s", self._saved_operation_mode)

                    if not self._saved_tariff:
                        site_tariff = site_info.get("tariff_content_v2") or site_info.get("tariff_content")
                        self._saved_tariff = _select_restorable_tesla_tariff(site_tariff)
                        if self._saved_tariff:
                            _LOGGER.info("Saved tariff from site_info fallback")
                        elif site_tariff:
                            _LOGGER.warning(
                                "Ignoring PowerSync force tariff from site_info as session restore baseline (name: %s)",
                                _tariff_display_name(site_tariff),
                            )

            # Step 3: Switch to autonomous mode
            if self._saved_operation_mode != "autonomous":
                _LOGGER.info("Switching to autonomous mode for session export...")
                async with session_http.post(
                    f"{api_base}/api/1/energy_sites/{self.site_id}/operation",
                    headers=headers,
                    json={"default_real_mode": "autonomous"},
                    timeout=aiohttp.ClientTimeout(total=30),
                ) as response:
                    if response.status == 200:
                        _LOGGER.info("Switched to autonomous mode")

            # Step 4: Create and upload session tariff
            session_tariff = self._create_session_tariff(session)
            success = await send_tariff_to_tesla(
                self.hass,
                self.site_id,
                session_tariff,
                current_token,
                current_provider,
                fleet_base_url=self.entry.data.get(CONF_FLEET_API_BASE_URL),
            )

            if success:
                self._in_session_mode = True
                self._session_start_time = dt_util.utcnow()
                self._active_session_code = session.code
                _LOGGER.warning(
                    "SESSION MODE ACTIVE: Tariff uploaded for %d octopoints/kWh export",
                    session.octopoints_per_kwh,
                )
            else:
                _LOGGER.error("Failed to upload session tariff")

            # Send push notification
            try:
                from .automations.actions import _send_expo_push
                rate_p = session.octopoints_per_kwh / self._octopoints_per_penny
                await _send_expo_push(
                    self.hass,
                    "Saving Session",
                    f"Active: {rate_p:.0f}p/kWh - exporting battery",
                )
            except Exception:
                pass

        except Exception as e:
            _LOGGER.error("Error entering session mode: %s", e, exc_info=True)

    def _create_session_tariff(self, session) -> dict:
        """Create Tesla tariff with massive sell rates during session window."""
        # Convert octopoints to GBP/kWh
        sell_rate = (session.octopoints_per_kwh / self._octopoints_per_penny) / 100
        # Buy rate must EXCEED sell rate to prevent grid charging arbitrage
        buy_rate = max(sell_rate * 2.0, 5.0)

        tariff = {
            "code": "OCTOPUS-SAVING-SESSION",
            "utility": "Octopus Saving Session",
            "name": f"Saving Session ({session.octopoints_per_kwh} octopoints/kWh)",
            "daily_charges": [{"name": "Grid Connection", "amount": 1.0}],
            "demand_charges": {"ALL": {"ALL": 0}},
            "energy_charges": {"ALL": {"ALL": 0}},
            "seasons": {
                "Summer": {
                    "fromMonth": 1,
                    "fromDay": 1,
                    "toMonth": 12,
                    "toDay": 31,
                    "tou_periods": {
                        "SESSION": {
                            "periods": [{"fromDayOfWeek": 0, "toDayOfWeek": 6, "fromHour": 0, "fromMinute": 0, "toHour": 0, "toMinute": 0}],
                            "buy": buy_rate,
                            "sell": sell_rate,
                        }
                    }
                }
            },
            "sell_tariff": {
                "name": "Session Export",
                "utility": "Octopus",
                "daily_charges": [],
                "demand_charges": {},
                "energy_charges": {"ALL": {"ALL": sell_rate}},
            }
        }

        _LOGGER.info(
            "Created session tariff: buy=%.2f GBP/kWh, sell=%.2f GBP/kWh (%d octopoints/kWh)",
            buy_rate, sell_rate, session.octopoints_per_kwh,
        )
        return tariff

    async def _exit_session_mode(self) -> None:
        """Restore saved tariff and operation mode after session ends."""
        _LOGGER.info("Saving session ended - restoring normal operation")

        try:
            current_token, current_provider = self._get_current_token()
            if not current_token:
                _LOGGER.warning("Cannot exit session mode — token temporarily unavailable")
                return
            session_http = async_get_clientsession(self.hass)
            headers = {
                "Authorization": f"Bearer {current_token}",
                "Content-Type": "application/json",
            }
            api_base = get_tesla_api_base_url(current_provider, self.entry.data.get(CONF_FLEET_API_BASE_URL))

            # Step 1: Switch to self_consumption mode first
            _LOGGER.info("Switching to self_consumption before tariff restore...")
            async with session_http.post(
                f"{api_base}/api/1/energy_sites/{self.site_id}/operation",
                headers=headers,
                json={"default_real_mode": "self_consumption"},
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status == 200:
                    _LOGGER.info("Switched to self_consumption mode")

            # Step 2: Restore saved tariff
            restore_tariff = _select_restorable_tesla_tariff(self._saved_tariff)
            if restore_tariff:
                _LOGGER.info("Restoring saved tariff...")
                success = await send_tariff_to_tesla(
                    self.hass,
                    self.site_id,
                    restore_tariff,
                    current_token,
                    current_provider,
                    fleet_base_url=self.entry.data.get(CONF_FLEET_API_BASE_URL),
                )
                if success:
                    _LOGGER.info("Restored saved tariff successfully")
                else:
                    _LOGGER.error("Failed to restore saved tariff")
            elif self._saved_tariff:
                _LOGGER.warning(
                    "Skipping restore of PowerSync force tariff after saving session (name: %s)",
                    _tariff_display_name(self._saved_tariff),
                )

            # Step 3: Wait for Tesla to process
            await asyncio.sleep(5)

            # Step 4: Restore original operation mode
            restore_mode = self._saved_operation_mode or "autonomous"
            _LOGGER.info("Restoring operation mode to: %s", restore_mode)
            async with session_http.post(
                f"{api_base}/api/1/energy_sites/{self.site_id}/operation",
                headers=headers,
                json={"default_real_mode": restore_mode},
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status == 200:
                    _LOGGER.info("Restored operation mode to %s", restore_mode)

            # Clear session state
            self._in_session_mode = False
            self._session_start_time = None
            self._active_session_code = None
            _LOGGER.info("SESSION MODE ENDED: Normal operation restored")

            # Send push notification
            try:
                from .automations.actions import _send_expo_push
                await _send_expo_push(
                    self.hass,
                    "Session Ended",
                    "Saving session complete - normal operation restored",
                )
            except Exception:
                pass

        except Exception as e:
            _LOGGER.error("Error exiting session mode: %s", e, exc_info=True)

    def get_status(self) -> dict:
        """Get current session manager status."""
        return {
            "enabled": True,
            "in_session_mode": self._in_session_mode,
            "active_session_code": self._active_session_code,
            "session_start_time": self._session_start_time.isoformat() if self._session_start_time else None,
        }


class GenericSavingSessionManager:
    """Battery-agnostic saving session manager using force_discharge/restore_normal.

    For non-Tesla batteries (Sigenergy, Sungrow, FoxESS, GoodWe).
    Uses service calls to force discharge during saving sessions.
    """

    def __init__(
        self,
        hass: HomeAssistant,
        entry: ConfigEntry,
        session_coordinator,
        battery_type: str,
        octopoints_per_penny: int = 8,
    ):
        """Initialize the generic saving session manager."""
        self.hass = hass
        self.entry = entry
        self._session_coordinator = session_coordinator
        self._battery_type = battery_type
        self._octopoints_per_penny = octopoints_per_penny

        # State tracking
        self._in_session_mode = False
        self._session_start_time: datetime | None = None
        self._active_session_code: str | None = None

        _LOGGER.info(
            "Generic Saving Session Manager initialized for %s", battery_type
        )

    @property
    def in_session_mode(self) -> bool:
        """Return whether currently in session mode."""
        return self._in_session_mode

    async def check_and_handle_sessions(self) -> None:
        """Check if a saving session is active and manage battery."""
        if not self._session_coordinator or not self._session_coordinator.data:
            return

        sessions = self._session_coordinator.data.get("sessions", [])
        active = next(
            (s for s in sessions if s.is_active() and s.joined and s.session_type == "saving"),
            None,
        )

        if active and not self._in_session_mode:
            await self._enter_session_mode(active)
        elif not active and self._in_session_mode:
            await self._exit_session_mode()

    async def _enter_session_mode(self, session) -> None:
        """Force discharge battery during saving session."""

        _LOGGER.warning(
            "%s SAVING SESSION STARTING: %s (%d octopoints/kWh) - force discharging",
            self._battery_type, session.code, session.octopoints_per_kwh,
        )

        try:
            await self.hass.services.async_call(
                DOMAIN, SERVICE_FORCE_DISCHARGE, {}, blocking=True
            )

            self._in_session_mode = True
            self._session_start_time = dt_util.utcnow()
            self._active_session_code = session.code
            _LOGGER.warning(
                "%s SESSION MODE ACTIVE: Battery force discharging",
                self._battery_type,
            )

            # Send push notification
            try:
                from .automations.actions import _send_expo_push
                rate_p = session.octopoints_per_kwh / self._octopoints_per_penny
                await _send_expo_push(
                    self.hass,
                    "Saving Session",
                    f"Active: {rate_p:.0f}p/kWh - discharging battery",
                )
            except Exception:
                pass

        except Exception as e:
            _LOGGER.error("%s: Error entering session mode: %s", self._battery_type, e, exc_info=True)

    async def _exit_session_mode(self) -> None:
        """Restore normal operation after saving session ends."""
        _LOGGER.info("%s: Saving session ended - restoring normal operation", self._battery_type)

        try:
            await self.hass.services.async_call(
                DOMAIN, SERVICE_RESTORE_NORMAL, {}, blocking=True
            )

            _LOGGER.info("%s: Normal operation restored after session", self._battery_type)

            # Send push notification
            try:
                from .automations.actions import _send_expo_push
                await _send_expo_push(
                    self.hass,
                    "Session Ended",
                    "Saving session complete - normal operation restored",
                )
            except Exception:
                pass

            self._in_session_mode = False
            self._session_start_time = None
            self._active_session_code = None

        except Exception as e:
            _LOGGER.error("%s: Error exiting session mode: %s", self._battery_type, e, exc_info=True)
            self._in_session_mode = False
            self._session_start_time = None
            self._active_session_code = None

    def get_status(self) -> dict:
        """Get current session manager status."""
        return {
            "enabled": True,
            "in_session_mode": self._in_session_mode,
            "active_session_code": self._active_session_code,
            "session_start_time": self._session_start_time.isoformat() if self._session_start_time else None,
            "battery_system": self._battery_type,
        }


async def async_migrate_entry(hass: HomeAssistant, config_entry: ConfigEntry) -> bool:
    """Migrate old entry to new format."""
    _LOGGER.info("Migrating PowerSync config entry from version %s", config_entry.version)

    if config_entry.version == 1:
        # Migrate from version 1 to version 2
        # Changes: tesla_site_id -> tesla_energy_site_id
        new_data = {**config_entry.data}

        if "tesla_site_id" in new_data:
            new_data["tesla_energy_site_id"] = new_data.pop("tesla_site_id")
            _LOGGER.info("Migrated tesla_site_id to tesla_energy_site_id")

        # Update the config entry with new data and version
        hass.config_entries.async_update_entry(
            config_entry, data=new_data, version=2
        )

        _LOGGER.info("Migration to version 2 complete")

    if config_entry.version == 2:
        # Migrate from version 2 to version 3
        # Changes:
        #   - solar_curtailment_enabled -> battery_curtailment_enabled
        #   - inverter_curtailment_enabled -> ac_inverter_curtailment_enabled
        new_data = {**config_entry.data}
        new_options = {**config_entry.options}

        # Migrate data keys
        if "solar_curtailment_enabled" in new_data:
            new_data["battery_curtailment_enabled"] = new_data.pop("solar_curtailment_enabled")
            _LOGGER.info("Migrated solar_curtailment_enabled to battery_curtailment_enabled (data)")

        if "inverter_curtailment_enabled" in new_data:
            new_data["ac_inverter_curtailment_enabled"] = new_data.pop("inverter_curtailment_enabled")
            _LOGGER.info("Migrated inverter_curtailment_enabled to ac_inverter_curtailment_enabled (data)")

        # Migrate options keys
        if "solar_curtailment_enabled" in new_options:
            new_options["battery_curtailment_enabled"] = new_options.pop("solar_curtailment_enabled")
            _LOGGER.info("Migrated solar_curtailment_enabled to battery_curtailment_enabled (options)")

        if "inverter_curtailment_enabled" in new_options:
            new_options["ac_inverter_curtailment_enabled"] = new_options.pop("inverter_curtailment_enabled")
            _LOGGER.info("Migrated inverter_curtailment_enabled to ac_inverter_curtailment_enabled (options)")

        # Update the config entry with new data, options, and version
        hass.config_entries.async_update_entry(
            config_entry, data=new_data, options=new_options, version=3
        )

        _LOGGER.info("Migration to version 3 complete")

    if config_entry.version == 3:
        # Migrate from version 3 to version 4
        # Flow Power v2 tariff integration — no data changes needed.
        # Missing CONF_FP_NETWORK/CONF_FP_TARIFF_CODE keys = legacy formula.
        hass.config_entries.async_update_entry(
            config_entry, version=4
        )
        _LOGGER.info("Migration to version 4 complete (Flow Power v2 tariff support)")

    if config_entry.version == 4:
        # Migrate from version 4 to version 5
        # Auto-enable Smart Optimization for existing entries that pre-date the
        # optimization_provider config step. New configs default to powersync_ml
        # (config_flow line 1059), but old entries lack the key entirely and
        # fell through to OPT_PROVIDER_NATIVE, silently disabling the optimizer.
        new_data = {**config_entry.data}
        if CONF_OPTIMIZATION_PROVIDER not in new_data:
            new_data[CONF_OPTIMIZATION_PROVIDER] = OPT_PROVIDER_POWERSYNC
            _LOGGER.info("Migration v4→v5: enabled Smart Optimization (was missing from config)")
        hass.config_entries.async_update_entry(
            config_entry, data=new_data, version=5
        )
        _LOGGER.info("Migration to version 5 complete")

    if config_entry.version == 5:
        # Migrate from version 5 to version 6
        # v4→v5 only set the key when missing, but some entries already had it
        # set to "native" from older config flow defaults. Upgrade those too,
        # unless the user explicitly disabled optimization via the app toggle.
        new_data = {**config_entry.data}
        user_disabled = config_entry.options.get(CONF_OPTIMIZATION_ENABLED) is False
        if new_data.get(CONF_OPTIMIZATION_PROVIDER) == OPT_PROVIDER_NATIVE and not user_disabled:
            new_data[CONF_OPTIMIZATION_PROVIDER] = OPT_PROVIDER_POWERSYNC
            _LOGGER.info("Migration v5→v6: upgraded native → Smart Optimization")
        hass.config_entries.async_update_entry(
            config_entry, data=new_data, version=6
        )
        _LOGGER.info("Migration to version 6 complete")

    if config_entry.version == 6:
        # Migrate from version 6 to version 7
        # Split Charge By Time prefill/deadline behavior from Profit Max while
        # preserving existing Profit Max users' prefill behavior.
        new_data = {**config_entry.data}
        new_options = {**config_entry.options}

        def _read_legacy(key: str, default: Any) -> Any:
            return new_options.get(key, new_data.get(key, default))

        if CONF_CHARGE_BY_TIME_ENABLED not in new_options and CONF_CHARGE_BY_TIME_ENABLED not in new_data:
            legacy_enabled = bool(
                _read_legacy(CONF_PROFIT_MAX_ENABLED, False)
            )
            new_data[CONF_CHARGE_BY_TIME_ENABLED] = legacy_enabled
            new_options[CONF_CHARGE_BY_TIME_ENABLED] = legacy_enabled
        if CONF_CHARGE_BY_TIME_TARGET_TIME not in new_options and CONF_CHARGE_BY_TIME_TARGET_TIME not in new_data:
            target_time = _read_legacy(
                CONF_PROFIT_MAX_TARGET_TIME,
                DEFAULT_CHARGE_BY_TIME_TARGET_TIME,
            )
            new_data[CONF_CHARGE_BY_TIME_TARGET_TIME] = target_time
            new_options[CONF_CHARGE_BY_TIME_TARGET_TIME] = target_time
        if CONF_CHARGE_BY_TIME_TARGET_SOC not in new_options and CONF_CHARGE_BY_TIME_TARGET_SOC not in new_data:
            target_soc = _read_legacy(
                CONF_PROFIT_MAX_TARGET_SOC,
                DEFAULT_CHARGE_BY_TIME_TARGET_SOC,
            )
            new_data[CONF_CHARGE_BY_TIME_TARGET_SOC] = target_soc
            new_options[CONF_CHARGE_BY_TIME_TARGET_SOC] = target_soc

        new_data[CONF_PROFIT_MAX_TARGET_TIME] = new_data[CONF_CHARGE_BY_TIME_TARGET_TIME]
        new_options[CONF_PROFIT_MAX_TARGET_TIME] = new_options[CONF_CHARGE_BY_TIME_TARGET_TIME]
        new_data[CONF_PROFIT_MAX_TARGET_SOC] = new_data[CONF_CHARGE_BY_TIME_TARGET_SOC]
        new_options[CONF_PROFIT_MAX_TARGET_SOC] = new_options[CONF_CHARGE_BY_TIME_TARGET_SOC]
        hass.config_entries.async_update_entry(
            config_entry,
            data=new_data,
            options=new_options,
            version=7,
        )
        _LOGGER.info("Migration to version 7 complete (Charge By Time split)")

    # Within-version migration: foxess_cloud_password → foxess_cloud_api_key
    if "foxess_cloud_password" in config_entry.data and "foxess_cloud_api_key" not in config_entry.data:
        new_data = {**config_entry.data}
        new_data.pop("foxess_cloud_password", None)
        new_data.pop("foxess_cloud_username", None)
        _LOGGER.info("Migrated FoxESS Cloud credentials: removed username/password (user should re-enter API key)")
        hass.config_entries.async_update_entry(config_entry, data=new_data)

    return True


def _normalise_tariff_rate_map(rates: Any) -> dict[str, float]:
    """Return comparable TOU rates rounded to avoid float representation noise."""
    if not isinstance(rates, dict):
        return {}
    normalised: dict[str, float] = {}
    for period, value in rates.items():
        try:
            normalised[str(period)] = round(float(value), 6)
        except (TypeError, ValueError):
            continue
    return normalised


def _tariff_charge_rates(tariff: dict[str, Any] | None, *, sell: bool) -> dict[str, float]:
    """Extract Summer TOU rates from Tesla tariff_content or tariff_content_v2 shapes."""
    if not isinstance(tariff, dict):
        return {}
    source = tariff.get("sell_tariff", {}) if sell else tariff
    if not isinstance(source, dict):
        return {}
    summer = source.get("energy_charges", {}).get("Summer", {})
    if not isinstance(summer, dict):
        return {}
    rates = summer.get("rates")
    if isinstance(rates, dict):
        return _normalise_tariff_rate_map(rates)
    return _normalise_tariff_rate_map(summer)


def _tesla_tariff_matches_readback(
    expected: dict[str, Any],
    observed: dict[str, Any] | None,
) -> bool:
    """Return True when site_info reflects the tariff we just uploaded."""
    if not isinstance(observed, dict):
        return False

    expected_buy = _tariff_charge_rates(expected, sell=False)
    observed_buy = _tariff_charge_rates(observed, sell=False)
    if expected_buy and observed_buy:
        if expected_buy != observed_buy:
            return False
        expected_sell = _tariff_charge_rates(expected, sell=True)
        observed_sell = _tariff_charge_rates(observed, sell=True)
        return not expected_sell or not observed_sell or expected_sell == observed_sell

    matched = 0
    for field in ("name", "utility", "code"):
        expected_value = expected.get(field)
        observed_value = observed.get(field)
        if expected_value is None or observed_value is None:
            continue
        if str(expected_value) != str(observed_value):
            return False
        matched += 1
    return matched > 0


async def _confirm_tesla_tariff_uploaded(
    session: aiohttp.ClientSession,
    api_base: str,
    site_id: str,
    headers: dict[str, str],
    tariff_data: dict[str, Any],
    *,
    attempts: int = 5,
    delay_seconds: float = 2.0,
) -> bool:
    """Poll Tesla site_info until the uploaded TOU tariff is visible."""
    url = f"{api_base}/api/1/energy_sites/{site_id}/site_info"
    for attempt in range(1, attempts + 1):
        if attempt > 1:
            await asyncio.sleep(delay_seconds)
        try:
            async with session.get(
                url,
                headers=headers,
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status != 200:
                    text = await response.text()
                    _LOGGER.warning(
                        "TOU readback check failed for site %s: %s - %s",
                        site_id,
                        response.status,
                        text[:200],
                    )
                    continue
                data = await response.json()
                site_info = data.get("response", {})
                observed = site_info.get("tariff_content_v2") or site_info.get("tariff_content")
                if _tesla_tariff_matches_readback(tariff_data, observed):
                    _LOGGER.info(
                        "Confirmed Tesla TOU tariff readback for site %s (attempt %d/%d)",
                        site_id,
                        attempt,
                        attempts,
                    )
                    return True
                _LOGGER.debug(
                    "Tesla TOU readback for site %s did not match yet (attempt %d/%d)",
                    site_id,
                    attempt,
                    attempts,
                )
        except Exception as err:
            _LOGGER.warning(
                "TOU readback check error for site %s (attempt %d/%d): %s",
                site_id,
                attempt,
                attempts,
                err,
            )
    return False


async def send_tariff_to_tesla(
    hass: HomeAssistant,
    site_id: str,
    tariff_data: dict[str, Any],
    api_token: str,
    api_provider: str = TESLA_PROVIDER_TESLEMETRY,
    max_retries: int = 3,
    timeout_seconds: int = 60,
    fleet_base_url: str | None = None,
    confirm_readback: bool = True,
    accepted_status: dict[str, bool] | None = None,
) -> bool:
    """Send tariff data to Tesla via the configured provider with retry logic.

    Args:
        hass: HomeAssistant instance
        site_id: Tesla energy site ID
        tariff_data: Tariff data to send
        api_token: API token (Teslemetry, Fleet API, or PowerSync proxy)
        api_provider: API provider (teslemetry, fleet_api, or powersync)
        max_retries: Maximum number of retry attempts (default: 3)
        timeout_seconds: Request timeout in seconds (default: 60)
        fleet_base_url: Regional Fleet API base URL override for EU/AP users.
        confirm_readback: Confirm the uploaded tariff appears in site_info before returning success.
        accepted_status: Optional mutable status populated with ``accepted=True``
            after Tesla accepts the upload, even if readback confirmation fails.

    Returns:
        True if successful, False otherwise
    """
    session = async_get_clientsession(hass)
    headers = {
        "Authorization": f"Bearer {api_token}",
        "Content-Type": "application/json",
    }

    payload = {
        "tou_settings": {
            "tariff_content_v2": tariff_data
        }
    }

    # DEBUG: Log the exact payload being sent to Tesla to diagnose flat pricing issues
    try:
        buy_prices = tariff_data.get("energy_charges", {}).get("Summer", {}).get("rates", {})
        sell_prices = tariff_data.get("sell_tariff", {}).get("energy_charges", {}).get("Summer", {}).get("rates", {})
        if buy_prices:
            buy_values = list(buy_prices.values())
            sell_values = list(sell_prices.values()) if sell_prices else [0]
            unique_buy = len(set(buy_values))
            unique_sell = len(set(sell_values))
            _LOGGER.debug(
                "TOU payload: %d buy prices (min=$%.4f, max=$%.4f, avg=$%.4f, unique=%d)",
                len(buy_values), min(buy_values), max(buy_values),
                sum(buy_values)/len(buy_values), unique_buy
            )
            _LOGGER.debug(
                "TOU payload: %d sell prices (min=$%.4f, max=$%.4f, unique=%d)",
                len(sell_values), min(sell_values), max(sell_values), unique_sell
            )
            # Log sample periods to verify variation
            sample_periods = ["PERIOD_00_00", "PERIOD_06_00", "PERIOD_12_00", "PERIOD_18_00"]
            for period in sample_periods:
                if period in buy_prices:
                    _LOGGER.debug(
                        "TOU sample: %s buy=$%.4f sell=$%.4f",
                        period, buy_prices[period], sell_prices.get(period, 0)
                    )
            # Log if prices appear flat (informational only)
            if unique_buy == 1:
                _LOGGER.debug(
                    "All buy prices are identical ($%.4f) - tariff will appear flat",
                    buy_values[0]
                )
            elif unique_buy <= 2:
                _LOGGER.debug(
                    "Only %d unique buy prices - tariff may appear flat",
                    unique_buy
                )
    except Exception as err:
        _LOGGER.debug("Error logging payload details: %s", err)

    # Use correct API base URL based on provider
    api_base = get_tesla_api_base_url(api_provider, fleet_base_url)
    url = f"{api_base}/api/1/energy_sites/{site_id}/time_of_use_settings"
    _LOGGER.debug("Sending TOU schedule via %s API", api_provider)
    last_error = None
    retry_after_delay = None  # Set by Retry-After header

    for attempt in range(max_retries):
        try:
            if attempt > 0:
                # Use Retry-After delay if available, otherwise exponential backoff
                wait_time = retry_after_delay or (2 ** attempt)
                retry_after_delay = None  # Reset for next attempt
                _LOGGER.info(
                    "TOU sync retry attempt %d/%d after %.0fs delay",
                    attempt + 1,
                    max_retries,
                    wait_time
                )
                await asyncio.sleep(wait_time)

            _LOGGER.debug(
                "Sending TOU schedule to Tesla via %s for site %s (attempt %d/%d)",
                api_provider,
                site_id,
                attempt + 1,
                max_retries
            )

            async with session.post(
                url,
                headers=headers,
                json=payload,
                timeout=aiohttp.ClientTimeout(total=timeout_seconds),
            ) as response:
                if response.status == 200:
                    result = await response.json()
                    if accepted_status is not None:
                        accepted_status["accepted"] = True
                    _LOGGER.info(
                        "Successfully synced TOU schedule to Tesla (attempt %d/%d)",
                        attempt + 1,
                        max_retries
                    )
                    _LOGGER.debug("Tesla API response: %s", result)
                    if not confirm_readback:
                        return True
                    if await _confirm_tesla_tariff_uploaded(
                        session,
                        api_base,
                        site_id,
                        headers,
                        tariff_data,
                    ):
                        return True
                    _LOGGER.error(
                        "TOU upload to Tesla was accepted but site_info did not confirm the tariff for site %s",
                        site_id,
                    )
                    return False

                # Log error and potentially retry
                error_text = await response.text()

                if response.status == 429:
                    # Rate limited — retry with Retry-After if provided
                    from .coordinator import _parse_retry_after
                    retry_after_delay = _parse_retry_after(response)
                    _LOGGER.warning(
                        "TOU sync rate limited 429 (attempt %d/%d): %s (retry-after: %s)",
                        attempt + 1,
                        max_retries,
                        error_text[:200],
                        f"{retry_after_delay:.0f}s" if retry_after_delay else "not set",
                    )
                    last_error = f"Rate limited 429"
                    continue  # Retry on 429

                if response.status >= 500:
                    # Server error — retry, respect Retry-After if present
                    from .coordinator import _parse_retry_after
                    retry_after_delay = _parse_retry_after(response)
                    _LOGGER.warning(
                        "Failed to sync TOU schedule: %s - %s (attempt %d/%d, will retry%s)",
                        response.status,
                        error_text[:200],
                        attempt + 1,
                        max_retries,
                        f", retry-after: {retry_after_delay:.0f}s" if retry_after_delay else "",
                    )
                    last_error = f"Server error {response.status}"
                    continue  # Retry on 5xx errors

                # Other 4xx client errors — don't retry
                _LOGGER.error(
                    "Failed to sync TOU schedule: %s - %s (client error, not retrying)",
                    response.status,
                    error_text
                )
                return False

        except aiohttp.ClientError as err:
            _LOGGER.warning(
                "Error communicating with Tesla via %s (attempt %d/%d): %s",
                api_provider,
                attempt + 1,
                max_retries,
                err
            )
            last_error = f"Network error: {err}"
            continue  # Retry on network errors

        except asyncio.TimeoutError:
            _LOGGER.warning(
                "Tesla API timeout via %s after %ds (attempt %d/%d)",
                api_provider,
                timeout_seconds,
                attempt + 1,
                max_retries
            )
            last_error = f"Timeout after {timeout_seconds}s"
            continue  # Retry on timeout

        except Exception as err:
            _LOGGER.exception(
                "Unexpected error syncing TOU schedule (attempt %d/%d): %s",
                attempt + 1,
                max_retries,
                err
            )
            last_error = f"Unexpected error: {err}"
            # Don't continue - unexpected errors might indicate a bug
            return False

    # All retries failed
    _LOGGER.error(
        "Failed to sync TOU schedule after %d attempts. Last error: %s",
        max_retries,
        last_error
    )
    return False


def get_tesla_api_token(hass: HomeAssistant, entry: ConfigEntry) -> tuple[str | None, str]:
    """
    Get the current Tesla API token and provider for this entry.

    Honors the user's configured CONF_TESLA_API_PROVIDER:
    - powersync: returns the saved psync_ token + powersync provider
    - fleet_api: returns a fresh access token from the tesla_fleet HA integration
    - teslemetry: returns the saved Teslemetry token + teslemetry provider

    The tesla_fleet integration handles token refresh internally and updates its
    config entry data. We always fetch the latest token.

    Returns:
        tuple: (token, provider) where provider is 'powersync', 'fleet_api', or 'teslemetry'
    """
    configured_provider = entry.data.get(CONF_TESLA_API_PROVIDER, TESLA_PROVIDER_TESLEMETRY)

    # PowerSync.cc cloud proxy: token is stored in the same slot as Teslemetry
    # but the proxy speaks Tesla Fleet API on /api/proxy/api/1/...
    if configured_provider == TESLA_PROVIDER_POWERSYNC:
        token = entry.data.get(CONF_TESLEMETRY_API_TOKEN)
        return (token, TESLA_PROVIDER_POWERSYNC) if token else (None, TESLA_PROVIDER_POWERSYNC)

    # Tesla Fleet API: pull a live token from the tesla_fleet integration
    if configured_provider == TESLA_PROVIDER_FLEET_API:
        tesla_fleet_entries = hass.config_entries.async_entries("tesla_fleet")
        for tesla_entry in tesla_fleet_entries:
            if tesla_entry.state == ConfigEntryState.LOADED:
                try:
                    if CONF_TOKEN in tesla_entry.data:
                        token_data = tesla_entry.data[CONF_TOKEN]
                        if CONF_ACCESS_TOKEN in token_data:
                            return token_data[CONF_ACCESS_TOKEN], TESLA_PROVIDER_FLEET_API
                except Exception as e:
                    _LOGGER.warning(f"Failed to extract token from Tesla Fleet integration: {e}")
        return None, TESLA_PROVIDER_FLEET_API

    # Teslemetry (default fallback)
    token = entry.data.get(CONF_TESLEMETRY_API_TOKEN)
    return (token, TESLA_PROVIDER_TESLEMETRY) if token else (None, TESLA_PROVIDER_TESLEMETRY)


def get_tesla_vehicle_api_token(
    hass: HomeAssistant, entry: ConfigEntry
) -> tuple[str | None, str]:
    """
    Get the Tesla API token + provider for *vehicle* commands.

    PowerSync.cc proxy doesn't expose vehicle endpoints, so when the energy
    site provider is PowerSync the user can pick a separate vehicle provider
    via CONF_TESLA_EV_API_PROVIDER (Tesla Fleet, Teslemetry, or None).

    On migration, when CONF_TESLA_EV_API_PROVIDER is unset, we default to:
      - 'tesla_fleet' if energy provider is fleet_api (same source as before)
      - 'teslemetry' if energy provider is teslemetry (same source as before)
      - 'none' if energy provider is powersync (vehicle commands disabled)

    Returns:
        tuple: (token, provider). provider is one of 'tesla_fleet',
        'teslemetry', or 'none'. token is None when provider is 'none' or
        when the selected provider isn't available.
    """
    from .const import (
        CONF_TESLA_EV_API_PROVIDER,
        CONF_TESLA_EV_TELEMETRY_TOKEN,
        TESLA_EV_API_PROVIDER_NONE,
        TESLA_EV_API_PROVIDER_FLEET_API,
        TESLA_EV_API_PROVIDER_TESLEMETRY,
    )

    ev_provider = entry.data.get(CONF_TESLA_EV_API_PROVIDER)
    if ev_provider is None:
        # Migration default — derive from the energy provider
        energy_provider = entry.data.get(CONF_TESLA_API_PROVIDER, TESLA_PROVIDER_TESLEMETRY)
        if energy_provider == TESLA_PROVIDER_FLEET_API:
            ev_provider = TESLA_EV_API_PROVIDER_FLEET_API
        elif energy_provider == TESLA_PROVIDER_TESLEMETRY:
            ev_provider = TESLA_EV_API_PROVIDER_TESLEMETRY
        else:
            ev_provider = TESLA_EV_API_PROVIDER_NONE

    if ev_provider == TESLA_EV_API_PROVIDER_NONE:
        return None, TESLA_EV_API_PROVIDER_NONE

    if ev_provider == TESLA_EV_API_PROVIDER_FLEET_API:
        tesla_fleet_entries = hass.config_entries.async_entries("tesla_fleet")
        for tesla_entry in tesla_fleet_entries:
            if tesla_entry.state == ConfigEntryState.LOADED:
                try:
                    if CONF_TOKEN in tesla_entry.data:
                        token_data = tesla_entry.data[CONF_TOKEN]
                        if CONF_ACCESS_TOKEN in token_data:
                            return token_data[CONF_ACCESS_TOKEN], TESLA_EV_API_PROVIDER_FLEET_API
                except Exception as e:
                    _LOGGER.warning("Failed to extract token from Tesla Fleet integration: %s", e)
        return None, TESLA_EV_API_PROVIDER_FLEET_API

    if ev_provider == TESLA_EV_API_PROVIDER_TESLEMETRY:
        # Prefer the dedicated EV Teslemetry token if set; otherwise fall
        # back to the energy-site Teslemetry token (when energy provider is
        # already Teslemetry, both share the same credentials).
        token = entry.data.get(CONF_TESLA_EV_TELEMETRY_TOKEN) or entry.data.get(CONF_TESLEMETRY_API_TOKEN)
        return (token, TESLA_EV_API_PROVIDER_TESLEMETRY) if token else (None, TESLA_EV_API_PROVIDER_TESLEMETRY)

    return None, TESLA_EV_API_PROVIDER_NONE


def _get_tesla_site_configs(
    hass: HomeAssistant, entry: ConfigEntry
) -> list[tuple[str, str, str]]:
    """Return list of (site_id, token, provider) for the Tesla gateway."""
    configs = []
    primary_id = entry.data.get(CONF_TESLA_ENERGY_SITE_ID)
    if primary_id:
        token, provider = get_tesla_api_token(hass, entry)
        if token:
            configs.append((primary_id, token, provider))
    return configs


def _calculate_cost_from_tariff(tariff_schedule: dict, time_series: list) -> dict | None:
    """Calculate import/export costs from tariff schedule and time_series energy data.

    For hourly entries (Tesla day period): matches each entry's timestamp to a TOU period
    and looks up the corresponding buy/sell rate.

    For daily entries (Sungrow/FoxESS, or Tesla week/month/year): uses weighted average
    rates across TOU periods for that day's season.

    Returns cost summary dict or None if calculation fails.
    """
    from datetime import datetime as dt

    try:
        buy_rates = tariff_schedule.get("buy_rates", {})
        sell_rates = tariff_schedule.get("sell_rates", {})
        seasons = tariff_schedule.get("seasons", {})
        tou_periods = tariff_schedule.get("tou_periods", {})

        if not buy_rates:
            return None

        def _parse_ts(ts_str: str) -> dt | None:
            """Parse ISO timestamp, handling Z suffix."""
            try:
                return dt.fromisoformat(ts_str.replace("Z", "+00:00"))
            except (ValueError, TypeError):
                return None

        # Detect hourly vs daily: >7 entries for what would be a single day = hourly
        is_hourly = len(time_series) > 7

        total_import_cost = 0.0
        total_export_earnings = 0.0

        if is_hourly:
            # Hourly entries: match each timestamp to a TOU period
            for entry in time_series:
                ts_str = entry.get("timestamp", "")
                if not ts_str:
                    continue
                ts = _parse_ts(ts_str)
                if ts is None:
                    continue

                hour = ts.hour
                dow = ts.weekday()  # 0=Monday
                tesla_dow = (dow + 1) % 7  # 0=Sunday
                month = ts.month

                # Find season for this entry's month
                entry_season = _find_season_for_month(seasons, month)
                # Get TOU periods for that season
                season_tou = seasons.get(entry_season, {}).get("tou_periods", tou_periods)

                # Match to TOU period
                matched_period = _match_tou_period(
                    season_tou,
                    hour,
                    tesla_dow,
                    buy_rates=buy_rates,
                    sell_rates=sell_rates,
                )

                buy_rate = buy_rates.get(matched_period, buy_rates.get("ALL", buy_rates.get("OFF_PEAK", 0)))
                sell_rate = sell_rates.get(matched_period, sell_rates.get("ALL", 0))

                grid_import_wh = entry.get("grid_import", 0)
                grid_export_wh = entry.get("grid_export", 0)

                total_import_cost += (grid_import_wh / 1000.0) * buy_rate
                total_export_earnings += (grid_export_wh / 1000.0) * sell_rate
        else:
            # Daily entries: use weighted average rate for each day
            for entry in time_series:
                ts_str = entry.get("timestamp", "")
                if not ts_str:
                    continue
                ts = _parse_ts(ts_str)
                if ts is None:
                    continue

                month = ts.month
                entry_season = _find_season_for_month(seasons, month)
                season_tou = seasons.get(entry_season, {}).get("tou_periods", tou_periods)

                avg_buy, avg_sell = _weighted_avg_rates(season_tou, buy_rates, sell_rates)

                grid_import_wh = entry.get("grid_import", 0)
                grid_export_wh = entry.get("grid_export", 0)

                total_import_cost += (grid_import_wh / 1000.0) * avg_buy
                total_export_earnings += (grid_export_wh / 1000.0) * avg_sell

        return {
            "import_cost": round(total_import_cost, 2),
            "export_earnings": round(total_export_earnings, 2),
            "net_cost": round(total_import_cost - total_export_earnings, 2),
            "estimated": True,
        }

    except Exception as e:
        _LOGGER.error(f"Error calculating cost from tariff: {e}", exc_info=True)
        return None


def _find_season_for_month(seasons: dict, month: int) -> str:
    """Find the season name for a given month."""
    for season_name, season_data in seasons.items():
        from_month = season_data.get("fromMonth", 1)
        to_month = season_data.get("toMonth", 12)
        if from_month <= to_month:
            if from_month <= month <= to_month:
                return season_name
        else:
            if month >= from_month or month <= to_month:
                return season_name
    return "All Year" if "All Year" in seasons else next(iter(seasons.keys()), "All Year")


def _match_tou_period(
    tou_periods: dict,
    hour: int,
    tesla_dow: int,
    *,
    buy_rates: dict | None = None,
    sell_rates: dict | None = None,
) -> str:
    """Match an hour and day-of-week to a TOU period name.

    Supports custom period names like PEAK_1, PEAK_2, OFF_PEAK_AUTO.
    SUPER_OFF_PEAK checked first, OFF_PEAK last as catch-all.
    """
    from datetime import datetime, timedelta
    from .tariff_time import find_matching_tou_period

    # 2024-01-07 was a Sunday, matching Tesla day 0.
    when = datetime(2024, 1, 7, hour) + timedelta(days=tesla_dow % 7)
    return find_matching_tou_period(
        tou_periods,
        when,
        default="OFF_PEAK",
        buy_rates=buy_rates,
        sell_rates=sell_rates,
    )


def _weighted_avg_rates(tou_periods: dict, buy_rates: dict, sell_rates: dict) -> tuple[float, float]:
    """Calculate weighted average buy/sell rates across all TOU periods for a full day.

    Weights each period by the number of hours it covers (averaged across all 7 days).
    """
    period_hours: dict[str, float] = {}
    total_hours = 0.0

    for period_name, period_data in tou_periods.items():
        if isinstance(period_data, dict) and "periods" in period_data:
            periods_list = period_data["periods"]
        elif isinstance(period_data, list):
            periods_list = period_data
        else:
            continue
        for p in periods_list:
            from_hour = p.get("fromHour", 0)
            to_hour = p.get("toHour", 24)
            from_dow = p.get("fromDayOfWeek", 0)
            to_dow = p.get("toDayOfWeek", 6)
            num_days = to_dow - from_dow + 1
            if from_hour <= to_hour:
                hours = (to_hour - from_hour) * num_days / 7.0
            else:
                hours = (24 - from_hour + to_hour) * num_days / 7.0
            period_hours[period_name] = period_hours.get(period_name, 0) + hours
            total_hours += hours

    if total_hours == 0:
        fallback_buy = buy_rates.get("ALL", buy_rates.get("OFF_PEAK", 0))
        fallback_sell = sell_rates.get("ALL", 0)
        return fallback_buy, fallback_sell

    avg_buy = 0.0
    avg_sell = 0.0
    for period_name, hours in period_hours.items():
        weight = hours / total_hours
        avg_buy += buy_rates.get(period_name, buy_rates.get("ALL", buy_rates.get("OFF_PEAK", 0))) * weight
        avg_sell += sell_rates.get(period_name, sell_rates.get("ALL", 0)) * weight

    return avg_buy, avg_sell


async def _calculate_cost_from_statistics(
    hass: HomeAssistant, period: str, end_date: str | None
) -> dict | None:
    """Calculate import/export costs from HA long-term statistics.

    Queries the recorder for hourly cost sensor data and sums it over the
    requested calendar period. Returns None if no statistics are available
    (e.g. new installation, sensors not yet recorded).
    """
    from datetime import datetime as dt, timedelta

    try:
        now = dt_util.now()

        # Determine end of period
        if end_date:
            try:
                end_dt = dt.strptime(end_date, "%Y-%m-%d").replace(
                    tzinfo=now.tzinfo
                )
                # End of that day
                end_dt = end_dt.replace(hour=23, minute=59, second=59)
            except ValueError:
                end_dt = now
        else:
            end_dt = now

        # Calculate start of period using calendar ranges
        if period == "day":
            start_dt = end_dt.replace(hour=0, minute=0, second=0, microsecond=0)
        elif period == "week":
            # Start of week (Monday)
            days_since_monday = end_dt.weekday()
            start_dt = (end_dt - timedelta(days=days_since_monday)).replace(
                hour=0, minute=0, second=0, microsecond=0
            )
        elif period == "month":
            start_dt = end_dt.replace(day=1, hour=0, minute=0, second=0, microsecond=0)
        elif period == "year":
            start_dt = end_dt.replace(
                month=1, day=1, hour=0, minute=0, second=0, microsecond=0
            )
        else:
            return None

        # Find cost sensor entity IDs
        import_cost_entity = None
        export_earnings_entity = None
        for state in hass.states.async_all("sensor"):
            eid = state.entity_id
            if eid.endswith("daily_import_cost") and "power_sync" in eid:
                import_cost_entity = eid
            elif eid.endswith("daily_export_earnings") and "power_sync" in eid:
                export_earnings_entity = eid

        if not import_cost_entity:
            return None

        # Query recorder statistics
        from homeassistant.components.recorder import get_instance
        from homeassistant.components.recorder.statistics import (
            statistics_during_period,
        )

        start_utc = dt_util.as_utc(start_dt)
        end_utc = dt_util.as_utc(end_dt)

        entity_ids = [import_cost_entity]
        if export_earnings_entity:
            entity_ids.append(export_earnings_entity)

        instance = get_instance(hass)
        stats = await instance.async_add_executor_job(
            statistics_during_period,
            hass,
            start_utc,
            end_utc,
            set(entity_ids),
            "hour",
            None,
            {"change"},
        )

        if not stats:
            return None

        # Sum hourly change values
        total_import_cost = 0.0
        total_export_earnings = 0.0

        if import_cost_entity in stats:
            for entry in stats[import_cost_entity]:
                change = entry.get("change")
                if change is not None:
                    total_import_cost += change

        if export_earnings_entity and export_earnings_entity in stats:
            for entry in stats[export_earnings_entity]:
                change = entry.get("change")
                if change is not None:
                    total_export_earnings += change

        # Only return if we got meaningful data
        if total_import_cost == 0 and total_export_earnings == 0:
            # Check if there are any stats at all (vs just zero cost)
            has_any = any(
                len(stats.get(eid, [])) > 0 for eid in entity_ids
            )
            if not has_any:
                return None

        return {
            "import_cost": round(total_import_cost, 2),
            "export_earnings": round(total_export_earnings, 2),
            "net_cost": round(total_import_cost - total_export_earnings, 2),
            "estimated": False,
        }

    except Exception as exc:
        _LOGGER.debug("Failed to calculate cost from statistics: %s", exc)
        return None


_CALENDAR_ENERGY_SUMMARY_COORDINATORS = (
    ("sigenergy_coordinator", "Sigenergy"),
    ("sungrow_coordinator", "Sungrow"),
    ("foxess_coordinator", "FoxESS"),
    ("goodwe_coordinator", "GoodWe"),
    ("alphaess_coordinator", "AlphaESS"),
    ("esy_sunhome_coordinator", "ESY Sunhome"),
    ("solax_coordinator", "Solax"),
    ("saj_h2_coordinator", "SAJ H2"),
    ("fronius_reserva_coordinator", "Fronius GEN24 storage"),
    ("neovolt_coordinator", "Neovolt"),
    ("solaredge_coordinator", "SolarEdge"),
)


def _find_calendar_energy_summary_source(
    hass: HomeAssistant, preferred_entry_id: str | None = None
) -> tuple[str | None, Any | None, str | None]:
    """Return the first non-Tesla coordinator that exposes daily energy totals."""
    domain_data = hass.data.get(DOMAIN, {})
    ordered_entry_data: list[tuple[str, dict[str, Any]]] = []

    if preferred_entry_id:
        preferred_data = domain_data.get(preferred_entry_id)
        if isinstance(preferred_data, dict):
            ordered_entry_data.append((preferred_entry_id, preferred_data))

    for entry_id, data in domain_data.items():
        if entry_id == preferred_entry_id:
            continue
        if isinstance(data, dict):
            ordered_entry_data.append((entry_id, data))

    for entry_id, data in ordered_entry_data:
        for coordinator_key, system_name in _CALENDAR_ENERGY_SUMMARY_COORDINATORS:
            coordinator = data.get(coordinator_key)
            coordinator_data = getattr(coordinator, "data", None)
            if (
                coordinator is not None
                and isinstance(coordinator_data, dict)
                and "energy_summary" in coordinator_data
            ):
                return system_name, coordinator, entry_id

    return None, None, None


def _energy_summary_wh(energy_data: dict[str, Any], key: str) -> float:
    """Read a kWh value from energy_summary and convert it to Wh."""
    try:
        return float(energy_data.get(key) or 0) * 1000
    except (TypeError, ValueError):
        return 0


def _calendar_entry_from_energy_summary(coordinator: Any) -> dict[str, Any]:
    """Build a mobile-compatible entry from current coordinator daily totals."""
    energy_data = {}
    if coordinator and getattr(coordinator, "data", None):
        energy_data = coordinator.data.get("energy_summary", {}) or {}

    return {
        "timestamp": dt_util.now().isoformat(),
        "solar_generation": _energy_summary_wh(energy_data, "pv_today_kwh"),
        "battery_discharge": _energy_summary_wh(energy_data, "discharge_today_kwh"),
        "battery_charge": _energy_summary_wh(energy_data, "charge_today_kwh"),
        "grid_import": _energy_summary_wh(energy_data, "grid_import_today_kwh"),
        "grid_export": _energy_summary_wh(energy_data, "grid_export_today_kwh"),
        "home_consumption": _energy_summary_wh(energy_data, "load_today_kwh"),
    }


def _calendar_entry_with_detail_aliases(entry: dict[str, Any]) -> dict[str, Any]:
    """Add aggregate Tesla-style fields without inventing flow splits."""
    enriched = dict(entry)
    solar_wh = enriched.get("solar_generation", 0) or 0
    battery_discharge_wh = enriched.get("battery_discharge", 0) or 0
    battery_charge_wh = enriched.get("battery_charge", 0) or 0
    grid_import_wh = enriched.get("grid_import", 0) or 0
    grid_export_wh = enriched.get("grid_export", 0) or 0
    home_consumption_wh = enriched.get("home_consumption", 0) or 0

    enriched.setdefault("solar_energy_exported", solar_wh)
    enriched.setdefault("battery_energy_exported", battery_discharge_wh)
    enriched.setdefault("battery_energy_imported", battery_charge_wh)
    enriched.setdefault("consumer_energy_imported", home_consumption_wh)
    enriched.setdefault("grid_energy_imported", grid_import_wh)
    enriched.setdefault("grid_energy_exported", grid_export_wh)
    return enriched


_CALENDAR_STATISTIC_FIELDS = {
    "solar_generation": "daily_solar_energy",
    "battery_discharge": "daily_battery_discharge",
    "battery_charge": "daily_battery_charge",
    "grid_import": "daily_grid_import",
    "grid_export": "daily_grid_export",
    "home_consumption": "daily_load",
}

_CALENDAR_STATISTIC_FIELD_ALIASES = {
    "battery_discharge": ("daily_battery_discharge_foxess",),
    "battery_charge": ("daily_battery_charge_foxess",),
}


def _calendar_statistic_suffixes(field: str) -> tuple[str, ...]:
    """Return entity suffixes that can provide one calendar-history field."""
    primary = _CALENDAR_STATISTIC_FIELDS[field]
    return (primary, *_CALENDAR_STATISTIC_FIELD_ALIASES.get(field, ()))


def _calendar_entry_has_energy(entry: dict[str, Any] | None) -> bool:
    """Return True when a calendar entry contains at least one energy value."""
    if not entry:
        return False
    return any((entry.get(field) or 0) > 0 for field in _CALENDAR_STATISTIC_FIELDS)


def _calendar_time_series_totals_kwh(
    time_series: list[dict[str, Any]],
) -> dict[str, float]:
    """Sum mobile calendar-history rows into kWh for support logging."""
    totals: dict[str, float] = {}
    for field in _CALENDAR_STATISTIC_FIELDS:
        total_wh = 0.0
        for entry in time_series:
            try:
                total_wh += float(entry.get(field) or 0)
            except (TypeError, ValueError):
                continue
        totals[field] = round(total_wh / 1000, 3)
    return totals


def _calendar_energy_state_wh(state: Any) -> float:
    """Convert a Home Assistant energy sensor state to Wh."""
    if state is None:
        return 0
    raw_value = getattr(state, "state", None)
    if raw_value in (None, "", "unknown", "unavailable"):
        return 0
    try:
        value = float(raw_value)
    except (TypeError, ValueError):
        return 0
    if value <= 0:
        return 0

    unit = str(
        getattr(state, "attributes", {}).get("unit_of_measurement", "")
    ).lower()
    if unit in ("wh", "watt-hour", "watt-hours"):
        return value
    return value * 1000


def _calendar_entry_from_energy_sensor_states(
    hass: HomeAssistant,
    preferred_entry_id: str | None,
) -> dict[str, Any] | None:
    """Build today's calendar entry from live PowerSync daily energy sensors."""
    entity_ids = _find_calendar_statistic_entity_ids(hass, preferred_entry_id)
    if not entity_ids:
        return None

    entry = {
        "timestamp": dt_util.now().isoformat(),
        "solar_generation": 0,
        "battery_discharge": 0,
        "battery_charge": 0,
        "grid_import": 0,
        "grid_export": 0,
        "home_consumption": 0,
    }
    for field, entity_id in entity_ids.items():
        entry[field] = _calendar_energy_state_wh(hass.states.get(entity_id))

    return entry if _calendar_entry_has_energy(entry) else None


def _merge_calendar_energy_entries(
    primary: dict[str, Any],
    fallback: dict[str, Any] | None,
) -> dict[str, Any]:
    """Fill missing/zero energy fields in primary from fallback."""
    if not fallback:
        return primary
    merged = dict(primary)
    for field in _CALENDAR_STATISTIC_FIELDS:
        if (merged.get(field) or 0) <= 0 and (fallback.get(field) or 0) > 0:
            merged[field] = fallback[field]
    return merged


def _calendar_current_entry(
    hass: HomeAssistant | None,
    coordinator: Any,
    preferred_entry_id: str | None = None,
) -> dict[str, Any]:
    """Build a current-day calendar entry using all live non-Tesla sources."""
    entry = _calendar_entry_from_energy_summary(coordinator)
    if hass is None:
        return _calendar_entry_with_detail_aliases(entry)
    state_entry = _calendar_entry_from_energy_sensor_states(hass, preferred_entry_id)
    return _calendar_entry_with_detail_aliases(
        _merge_calendar_energy_entries(entry, state_entry)
    )


def _calendar_time_series_from_energy_summary(
    coordinator: Any,
    hass: HomeAssistant | None = None,
    entry_id: str | None = None,
) -> list[dict[str, Any]]:
    """Build a mobile-compatible one-point history from live daily totals."""
    return [_calendar_current_entry(hass, coordinator, entry_id)]


def _calendar_residual_entry(
    current_entry: dict[str, Any],
    existing_rows: list[dict[str, Any]],
) -> dict[str, Any] | None:
    """Return the current live total minus recorder rows already emitted."""
    residual = {
        "timestamp": current_entry.get("timestamp") or dt_util.now().isoformat(),
        "solar_generation": 0,
        "battery_discharge": 0,
        "battery_charge": 0,
        "grid_import": 0,
        "grid_export": 0,
        "home_consumption": 0,
    }
    for field in _CALENDAR_STATISTIC_FIELDS:
        try:
            current_wh = float(current_entry.get(field) or 0)
        except (TypeError, ValueError):
            current_wh = 0
        emitted_wh = 0.0
        for row in existing_rows:
            try:
                emitted_wh += float(row.get(field) or 0)
            except (TypeError, ValueError):
                continue
        residual[field] = max(0, current_wh - emitted_wh)

    return (
        _calendar_entry_with_detail_aliases(residual)
        if _calendar_entry_has_energy(residual)
        else None
    )


def _calendar_period_range(period: str, end_date: str | None) -> tuple[datetime, datetime] | None:
    """Return local start/end datetimes for a calendar-history request."""
    now = dt_util.now()
    if end_date:
        try:
            parsed_date = datetime.strptime(end_date, "%Y-%m-%d").date()
        except ValueError:
            parsed_date = now.date()
    else:
        parsed_date = now.date()

    end_day_start = datetime(
        parsed_date.year,
        parsed_date.month,
        parsed_date.day,
        tzinfo=now.tzinfo,
    )

    if period == "day":
        start_dt = end_day_start
    elif period == "week":
        start_dt = end_day_start - timedelta(days=end_day_start.weekday())
    elif period == "month":
        start_dt = end_day_start.replace(day=1)
    elif period == "year":
        start_dt = end_day_start.replace(month=1, day=1)
    else:
        return None

    end_dt = end_day_start + timedelta(days=1)
    if start_dt.date() <= now.date() <= end_day_start.date():
        end_dt = now

    return start_dt, end_dt


def _calendar_range_includes_today(
    start_dt: datetime,
    end_dt: datetime,
    now: datetime | None = None,
) -> bool:
    """Return True when a history range should include today's live row."""
    now = now or dt_util.now()
    today_start = datetime(now.year, now.month, now.day, tzinfo=now.tzinfo)
    return start_dt <= now and end_dt > today_start


def _calendar_statistics_end_dt(
    period: str,
    end_dt: datetime,
    now: datetime,
    includes_today: bool,
) -> datetime:
    """Return the statistics query end while avoiding duplicated live totals."""
    if not includes_today:
        return end_dt
    if period == "day":
        return end_dt
    today_start = datetime(now.year, now.month, now.day, tzinfo=now.tzinfo)
    return min(end_dt, today_start)


def _calendar_history_bucket_timestamp(
    timestamp: datetime,
    period: str,
) -> str:
    """Return the calendar-history bucket timestamp for a raw recorder state."""
    local_timestamp = dt_util.as_local(timestamp)
    if period == "day":
        bucket = local_timestamp.replace(minute=0, second=0, microsecond=0)
    else:
        bucket = local_timestamp.replace(hour=0, minute=0, second=0, microsecond=0)
    return bucket.isoformat()


def _calendar_time_series_from_state_history_rows(
    history: dict[str, list[Any]],
    entity_to_field: dict[str, str],
    period: str,
    start_dt: datetime,
    end_dt: datetime,
) -> list[dict[str, Any]]:
    """Build calendar-history deltas from raw daily sensor state history."""
    time_series: dict[str, dict[str, Any]] = {}

    for entity_id, field in entity_to_field.items():
        states = sorted(
            (history or {}).get(entity_id, []) or [],
            key=lambda state: (
                getattr(state, "last_changed", None)
                or getattr(state, "last_updated", None)
                or start_dt
            ),
        )
        previous_wh: float | None = None
        previous_date = None
        for state in states:
            state_time = getattr(state, "last_changed", None) or getattr(
                state, "last_updated", None
            )
            if state_time is None:
                continue

            local_time = dt_util.as_local(state_time)
            if local_time < start_dt or local_time >= end_dt:
                continue

            state_date = local_time.date()
            current_wh = _calendar_energy_state_wh(state)
            if current_wh <= 0:
                if previous_wh is None or previous_date != state_date:
                    previous_wh = current_wh
                    previous_date = state_date
                continue

            # Daily sensors reset to zero around midnight. Treat a lower value
            # on a later local date as a new-day delta. Ignore same-day drops,
            # which can appear as transient restore/reload states and would
            # otherwise duplicate the next good cumulative value.
            if previous_wh is None or previous_date != state_date:
                delta_wh = current_wh
            elif current_wh >= previous_wh:
                delta_wh = current_wh - previous_wh
            else:
                continue
            previous_wh = current_wh
            previous_date = state_date
            if delta_wh <= 0:
                continue

            timestamp = _calendar_history_bucket_timestamp(local_time, period)
            row = time_series.setdefault(
                timestamp,
                {
                    "timestamp": timestamp,
                    "solar_generation": 0,
                    "battery_discharge": 0,
                    "battery_charge": 0,
                    "grid_import": 0,
                    "grid_export": 0,
                    "home_consumption": 0,
                },
            )
            row[field] += delta_wh

    return [
        _calendar_entry_with_detail_aliases(time_series[key])
        for key in sorted(time_series)
    ]


async def _calendar_time_series_from_state_history(
    hass: HomeAssistant,
    period: str,
    start_dt: datetime,
    end_dt: datetime,
    entity_ids: dict[str, str],
) -> list[dict[str, Any]]:
    """Build calendar history from raw recorder states when statistics are empty."""
    if not entity_ids or end_dt <= start_dt:
        return []

    try:
        from homeassistant.components.recorder import get_instance
        from homeassistant.components.recorder.history import get_significant_states

        recorder = get_instance(hass)
        if recorder is None:
            return []

        entity_to_field = {
            entity_id: field for field, entity_id in entity_ids.items()
        }
        history = await recorder.async_add_executor_job(
            get_significant_states,
            hass,
            start_dt,
            end_dt,
            list(entity_to_field),
        )
        rows = await hass.async_add_executor_job(
            _calendar_time_series_from_state_history_rows,
            history or {},
            entity_to_field,
            period,
            start_dt,
            end_dt,
        )
        if rows:
            _LOGGER.info(
                "Calendar history using recorder state fallback: rows=%d",
                len(rows),
            )
        return rows
    except Exception as exc:
        _LOGGER.debug("Failed to build calendar history from state history: %s", exc)
        return []


def _find_calendar_statistic_entity_ids(
    hass: HomeAssistant,
    preferred_entry_id: str | None,
) -> dict[str, str]:
    """Find PowerSync daily energy sensor entity IDs for recorder statistics."""
    from homeassistant.helpers import entity_registry as er

    registry = er.async_get(hass)
    entity_ids: dict[str, str] = {}

    for entity in registry.entities.values():
        if entity.domain != "sensor" or entity.platform != DOMAIN:
            continue
        unique_id = str(entity.unique_id or "")
        if preferred_entry_id and not unique_id.startswith(f"{preferred_entry_id}_"):
            continue

        for field in _CALENDAR_STATISTIC_FIELDS:
            for suffix in _calendar_statistic_suffixes(field):
                if unique_id.endswith(f"_{suffix}") and hass.states.get(entity.entity_id):
                    entity_ids.setdefault(field, entity.entity_id)
                    break

    if len(entity_ids) == len(_CALENDAR_STATISTIC_FIELDS):
        return entity_ids

    for state in hass.states.async_all("sensor"):
        object_id = state.entity_id.split(".", 1)[-1]
        if "power_sync" not in object_id:
            continue
        for field in _CALENDAR_STATISTIC_FIELDS:
            for suffix in _calendar_statistic_suffixes(field):
                if object_id.endswith(suffix):
                    entity_ids.setdefault(field, state.entity_id)
                    break

    return entity_ids


async def _calendar_time_series_from_statistics(
    hass: HomeAssistant,
    period: str,
    end_date: str | None,
    coordinator: Any,
    preferred_entry_id: str | None,
) -> list[dict[str, Any]]:
    """Build calendar history from HA recorder statistics for daily sensors."""
    range_result = _calendar_period_range(period, end_date)
    if not range_result:
        return []

    start_dt, end_dt = range_result
    now = dt_util.now()
    includes_today = _calendar_range_includes_today(start_dt, end_dt, now)
    statistic_end_dt = _calendar_statistics_end_dt(
        period,
        end_dt,
        now,
        includes_today,
    )

    entity_ids = _find_calendar_statistic_entity_ids(hass, preferred_entry_id)
    if not entity_ids:
        return _calendar_time_series_from_energy_summary(coordinator) if includes_today else []

    time_series: dict[str, dict[str, Any]] = {}

    if statistic_end_dt > start_dt:
        try:
            from homeassistant.components.recorder import get_instance
            from homeassistant.components.recorder.statistics import (
                statistics_during_period,
            )

            statistic_period = "hour" if period == "day" else "day"
            start_utc = dt_util.as_utc(start_dt)
            end_utc = dt_util.as_utc(statistic_end_dt)
            instance = get_instance(hass)
            stats = await instance.async_add_executor_job(
                statistics_during_period,
                hass,
                start_utc,
                end_utc,
                set(entity_ids.values()),
                statistic_period,
                None,
                {"change"},
            )

            entity_to_field = {entity_id: field for field, entity_id in entity_ids.items()}
            for entity_id, entries in (stats or {}).items():
                field = entity_to_field.get(entity_id)
                if not field:
                    continue
                for stat_entry in entries:
                    change = stat_entry.get("change")
                    if change is None:
                        continue
                    start = stat_entry.get("start")
                    if not isinstance(start, datetime):
                        continue
                    local_start = dt_util.as_local(start)
                    timestamp = local_start.isoformat()
                    row = time_series.setdefault(
                        timestamp,
                        {
                            "timestamp": timestamp,
                            "solar_generation": 0,
                            "battery_discharge": 0,
                            "battery_charge": 0,
                            "grid_import": 0,
                            "grid_export": 0,
                            "home_consumption": 0,
                        },
                    )
                    row[field] += max(0, float(change)) * 1000
        except Exception as exc:
            _LOGGER.debug("Failed to build calendar history from statistics: %s", exc)

    rows = [
        _calendar_entry_with_detail_aliases(time_series[key])
        for key in sorted(time_series)
    ]
    if not rows and statistic_end_dt > start_dt:
        rows = await _calendar_time_series_from_state_history(
            hass,
            period,
            start_dt,
            statistic_end_dt,
            entity_ids,
        )
    if includes_today:
        current_entry = _calendar_current_entry(
            hass, coordinator, preferred_entry_id
        )
        if _calendar_entry_has_energy(current_entry):
            if period == "day" and rows:
                residual_entry = _calendar_residual_entry(current_entry, rows)
                if residual_entry:
                    rows.append(residual_entry)
            else:
                rows.append(current_entry)

    return rows


async def _calendar_result_from_energy_summary(
    hass: HomeAssistant,
    period: str,
    end_date: str | None,
    coordinator: Any,
    entry_id: str | None = None,
    tariff_schedule: dict | None = None,
    source_system: str | None = None,
) -> dict[str, Any]:
    """Return calendar-history response data for energy-summary based systems."""
    time_series = await _calendar_time_series_from_statistics(
        hass,
        period,
        end_date,
        coordinator,
        entry_id,
    )
    if not time_series:
        range_result = _calendar_period_range(period, end_date)
        includes_today = bool(
            range_result
            and _calendar_range_includes_today(range_result[0], range_result[1])
        )
        time_series = (
            _calendar_time_series_from_energy_summary(
                coordinator, hass, entry_id
            )
            if includes_today
            else []
        )
    result = {
        "success": True,
        "period": period,
        "time_series": time_series,
        "serial_number": None,
        "installation_date": None,
    }

    cost_summary = await _calculate_cost_from_statistics(hass, period, end_date)
    if not cost_summary and tariff_schedule:
        cost_summary = _calculate_cost_from_tariff(tariff_schedule, time_series)
    if cost_summary:
        load_kwh = sum(e.get("home_consumption", 0) for e in time_series) / 1000
        if load_kwh > 0:
            cost_summary["avg_cost_per_kwh"] = round(
                ((cost_summary.get("import_cost") or 0) - (cost_summary.get("export_earnings") or 0)) / load_kwh,
                4,
            )
        result["cost_summary"] = cost_summary

    totals = _calendar_time_series_totals_kwh(time_series)
    _LOGGER.info(
        "Calendar history energy-summary response: source=%s period=%s "
        "end_date=%s rows=%d totals_kwh solar=%.3f battery_discharge=%.3f "
        "battery_charge=%.3f grid_import=%.3f grid_export=%.3f home=%.3f",
        source_system or "unknown",
        period,
        end_date,
        len(time_series),
        totals["solar_generation"],
        totals["battery_discharge"],
        totals["battery_charge"],
        totals["grid_import"],
        totals["grid_export"],
        totals["home_consumption"],
    )

    return result


class CalendarHistoryView(HomeAssistantView):
    """HTTP view to get calendar history for mobile app."""

    url = "/api/power_sync/calendar_history"
    name = "api:power_sync:calendar_history"
    requires_auth = True
    _CACHE_TTL_SECONDS = 300
    _REQUEST_TIMEOUT_SECONDS = 6.0

    def __init__(self, hass: HomeAssistant):
        """Initialize the view."""
        self._hass = hass
        self._cache: dict[tuple[str, str, str], tuple[float, dict[str, Any], int]] = {}
        self._inflight: dict[tuple[str, str, str], asyncio.Task[tuple[dict[str, Any], int]]] = {}

    def _calendar_cache_key(
        self,
        tesla_coordinator: Any,
        period: str,
        end_date: str | None,
    ) -> tuple[str, str, str]:
        """Return a stable cache key for one calendar-history request."""
        site_id = str(getattr(tesla_coordinator, "site_id", "") or "unknown")
        return (site_id, period, end_date or "")

    def _cached_calendar_result(
        self,
        key: tuple[str, str, str],
    ) -> tuple[dict[str, Any], int] | None:
        """Return a fresh cached calendar-history response, if one exists."""
        cached = self._cache.get(key)
        if not cached:
            return None
        cached_at, result, status = cached
        if time.monotonic() - cached_at > self._CACHE_TTL_SECONDS:
            return None
        response = dict(result)
        response["cached"] = True
        return response, status

    def _store_calendar_result(
        self,
        key: tuple[str, str, str],
        result: dict[str, Any],
        status: int,
    ) -> None:
        """Cache successful calendar-history responses for short-term reuse."""
        if status == 200 and result.get("success"):
            self._cache[key] = (time.monotonic(), dict(result), status)

    async def _build_calendar_history_response(
        self,
        *,
        tesla_coordinator: Any,
        tariff_schedule: dict | None,
        period: str,
        end_date: str | None,
    ) -> tuple[dict[str, Any], int]:
        """Fetch and shape calendar history without blocking duplicate requests."""
        try:
            history = await tesla_coordinator.async_get_calendar_history(period=period, end_date=end_date)
        except Exception as e:
            _LOGGER.error(f"Error fetching calendar history: {e}")
            return {"success": False, "error": str(e)}, 500

        if not history:
            _LOGGER.error("Failed to fetch calendar history")
            return {
                "success": False,
                "error": "Failed to fetch calendar history from Tesla API",
            }, 500

        time_series = []
        for entry_data in history.get("time_series", []):
            time_series.append({
                "timestamp": entry_data.get("timestamp", ""),
                # Normalized fields for compatibility
                "solar_generation": entry_data.get("solar_energy_exported", 0),
                "battery_discharge": entry_data.get("battery_energy_exported", 0),
                "battery_charge": entry_data.get("battery_energy_imported", 0),
                "grid_import": entry_data.get("grid_energy_imported", 0),
                "grid_export": entry_data.get("grid_energy_exported_from_solar", 0) + entry_data.get("grid_energy_exported_from_battery", 0),
                "home_consumption": entry_data.get("consumer_energy_imported_from_grid", 0) + entry_data.get("consumer_energy_imported_from_solar", 0) + entry_data.get("consumer_energy_imported_from_battery", 0),
                # Detailed breakdown fields from Tesla API (for detail screens)
                "solar_energy_exported": entry_data.get("solar_energy_exported", 0),
                "battery_energy_exported": entry_data.get("battery_energy_exported", 0),
                "battery_energy_imported_from_grid": entry_data.get("battery_energy_imported_from_grid", 0),
                "battery_energy_imported_from_solar": entry_data.get("battery_energy_imported_from_solar", 0),
                "consumer_energy_imported_from_grid": entry_data.get("consumer_energy_imported_from_grid", 0),
                "consumer_energy_imported_from_solar": entry_data.get("consumer_energy_imported_from_solar", 0),
                "consumer_energy_imported_from_battery": entry_data.get("consumer_energy_imported_from_battery", 0),
                "grid_energy_exported_from_solar": entry_data.get("grid_energy_exported_from_solar", 0),
                "grid_energy_exported_from_battery": entry_data.get("grid_energy_exported_from_battery", 0),
            })

        result = {
            "success": True,
            "period": period,
            "time_series": time_series,
            "serial_number": history.get("serial_number"),
            "installation_date": history.get("installation_date"),
        }
        cost_summary = await _calculate_cost_from_statistics(self._hass, period, end_date)
        if not cost_summary and tariff_schedule:
            cost_summary = _calculate_cost_from_tariff(tariff_schedule, time_series)
        if cost_summary:
            load_kwh = sum(e.get("home_consumption", 0) for e in time_series) / 1000
            if load_kwh > 0:
                cost_summary["avg_cost_per_kwh"] = round(
                    ((cost_summary.get("import_cost") or 0) - (cost_summary.get("export_earnings") or 0)) / load_kwh, 4
                )
            result["cost_summary"] = cost_summary

        _LOGGER.info(f"✅ Calendar history HTTP response: {len(time_series)} records for period '{period}'")
        return result, 200

    async def get(self, request: web.Request) -> web.Response:
        """Handle GET request for calendar history."""
        # Get period from query params (default: day)
        period = request.query.get("period", "day")
        # Get end_date from query params (format: YYYY-MM-DD)
        end_date = request.query.get("end_date")

        # Validate period
        valid_periods = ["day", "week", "month", "year"]
        if period not in valid_periods:
            return web.json_response(
                {"success": False, "error": f"Invalid period. Must be one of: {valid_periods}"},
                status=400
            )

        _LOGGER.info(f"📊 Calendar history HTTP request for period: {period}, end_date: {end_date}")

        # Find the power_sync entry and coordinator
        # Check ALL entries, not just the first one (important during reload)
        tesla_coordinator = None
        for _entry_id, data in self._hass.data.get(DOMAIN, {}).items():
            if isinstance(data, dict):
                # Look for Tesla coordinator (this is the main data source for calendar history)
                if "tesla_coordinator" in data and data["tesla_coordinator"] is not None:
                    tesla_coordinator = data["tesla_coordinator"]
                    break  # Found it, no need to continue

        # Look up tariff schedule for cost calculation (shared across all battery types)
        tariff_schedule = None
        for _eid, _data in self._hass.data.get(DOMAIN, {}).items():
            if isinstance(_data, dict):
                ts = _data.get("tariff_schedule")
                if ts and ts.get("buy_rates"):
                    tariff_schedule = ts
                    break

        summary_system, summary_coordinator, summary_entry_id = _find_calendar_energy_summary_source(self._hass)
        if summary_coordinator and not tesla_coordinator:
            _LOGGER.info(
                "Calendar history using %s daily energy summary",
                summary_system,
            )
            result = await _calendar_result_from_energy_summary(
                self._hass,
                period,
                end_date,
                summary_coordinator,
                summary_entry_id,
                tariff_schedule,
                summary_system,
            )
            return web.json_response(result)

        if not tesla_coordinator:
            # Check if we have ANY power_sync entries - if yes, system might still be loading
            has_entries = bool(self._hass.data.get(DOMAIN, {}))
            if has_entries:
                _LOGGER.debug("Calendar history requested but Tesla coordinator not ready yet (system loading)")
                return web.json_response(
                    {
                        "success": False,
                        "error": "System is still loading, please retry",
                        "reason": "loading"
                    },
                    status=200  # Return 200 with error in body so mobile app handles gracefully
                )
            else:
                _LOGGER.debug("Calendar history requested but Tesla coordinator not available (non-Tesla system)")
                return web.json_response(
                    {
                        "success": False,
                        "error": "Calendar history requires Tesla Powerwall",
                        "reason": "tesla_not_configured"
                    },
                    status=200  # Return 200 with error in body so mobile app handles gracefully
                )

        cache_key = self._calendar_cache_key(tesla_coordinator, period, end_date)
        cached = self._cached_calendar_result(cache_key)
        if cached:
            result, status = cached
            return web.json_response(result, status=status)

        task = self._inflight.get(cache_key)
        if task and task.done():
            try:
                result, status = task.result()
                self._store_calendar_result(cache_key, result, status)
                return web.json_response(result, status=status)
            finally:
                self._inflight.pop(cache_key, None)

        if not task:
            task = self._hass.async_create_task(
                self._build_calendar_history_response(
                    tesla_coordinator=tesla_coordinator,
                    tariff_schedule=tariff_schedule,
                    period=period,
                    end_date=end_date,
                ),
                name=f"powersync_calendar_history_{period}",
            )
            self._inflight[cache_key] = task

        try:
            result, status = await asyncio.wait_for(
                asyncio.shield(task),
                timeout=self._REQUEST_TIMEOUT_SECONDS,
            )
        except (asyncio.TimeoutError, TimeoutError):
            cached = self._cache.get(cache_key)
            if cached:
                _cached_at, result, status = cached
                stale_result = dict(result)
                stale_result["cached"] = True
                stale_result["stale"] = True
                stale_result["refresh_pending"] = True
                _LOGGER.warning(
                    "Calendar history still loading after %.1fs; returning stale cache",
                    self._REQUEST_TIMEOUT_SECONDS,
                )
                return web.json_response(stale_result, status=status)

            _LOGGER.warning(
                "Calendar history still loading after %.1fs; returning loading response",
                self._REQUEST_TIMEOUT_SECONDS,
            )
            return web.json_response(
                {
                    "success": False,
                    "error": "Calendar history is still loading, please retry",
                    "reason": "loading",
                    "refresh_pending": True,
                },
                status=200,
            )

        if task.done():
            self._inflight.pop(cache_key, None)
        self._store_calendar_result(cache_key, result, status)
        return web.json_response(result, status=status)


def _is_history_relink_entry(entry: ConfigEntry) -> bool:
    """Return True when an entry can use Sungrow history relinking."""
    return (
        entry.data.get(CONF_BATTERY_SYSTEM) == BATTERY_SYSTEM_SUNGROW
        or bool(entry.data.get(CONF_SUNGROW_HOST))
        or bool(entry.options.get(CONF_SUNGROW_HOST))
    )


def _resolve_history_relink_entry(
    hass: HomeAssistant,
    entry_id: str | None = None,
    default_entry: ConfigEntry | None = None,
) -> ConfigEntry | None:
    """Resolve the entry used by history relink preview/apply calls."""
    if entry_id:
        for candidate in hass.config_entries.async_entries(DOMAIN):
            if candidate.entry_id == entry_id:
                return candidate
        return None

    if default_entry is not None and _is_history_relink_entry(default_entry):
        return default_entry

    for candidate in hass.config_entries.async_entries(DOMAIN):
        if _is_history_relink_entry(candidate):
            return candidate
    return default_entry


class HistoryRelinkView(HomeAssistantView):
    """HTTP view to preview/apply Sungrow history relinks."""

    url = "/api/power_sync/history_relink"
    name = "api:power_sync:history_relink"
    requires_auth = True

    def __init__(self, hass: HomeAssistant):
        """Initialize the view."""
        self._hass = hass

    async def get(self, request: web.Request) -> web.Response:
        """Handle history relink preview requests."""
        entry = _resolve_history_relink_entry(
            self._hass,
            request.query.get("entry_id"),
        )
        if entry is None:
            return web.json_response(
                {"success": False, "error": "PowerSync entry not found"},
                status=404,
            )
        if not _is_history_relink_entry(entry):
            return web.json_response(
                {
                    "success": False,
                    "error": "History relink is only available for Sungrow entries",
                },
                status=400,
            )
        return web.json_response(preview_history_relink(self._hass, entry))

    async def post(self, request: web.Request) -> web.Response:
        """Handle history relink apply requests."""
        try:
            data = await request.json()
        except Exception:
            data = {}

        entry = _resolve_history_relink_entry(
            self._hass,
            data.get("entry_id"),
        )
        if entry is None:
            return web.json_response(
                {"success": False, "error": "PowerSync entry not found"},
                status=404,
            )
        if not _is_history_relink_entry(entry):
            return web.json_response(
                {
                    "success": False,
                    "error": "History relink is only available for Sungrow entries",
                },
                status=400,
            )
        if data.get("confirm") is not True:
            return web.json_response(
                {"success": False, "error": "confirm must be true"},
                status=400,
            )

        return web.json_response(apply_history_relink(self._hass, entry))


class PowerwallSettingsView(HomeAssistantView):
    """HTTP view to get Powerwall settings for mobile app Controls."""

    url = "/api/power_sync/powerwall_settings"
    name = "api:power_sync:powerwall_settings"
    requires_auth = True

    def __init__(self, hass: HomeAssistant):
        """Initialize the view."""
        self._hass = hass

    async def get(self, request: web.Request) -> web.Response:
        """Handle GET request for Powerwall settings."""
        _LOGGER.info("⚙️ Powerwall settings HTTP request")

        # Find the power_sync entry and get token/site_id
        entry = None
        for config_entry in self._hass.config_entries.async_entries(DOMAIN):
            entry = config_entry
            break

        if not entry:
            return web.json_response(
                {"success": False, "error": "PowerSync not configured"},
                status=503
            )

        # Check if this is a non-Tesla setup - Powerwall settings may not apply.
        is_sigenergy = bool(entry.data.get(CONF_SIGENERGY_STATION_ID))
        is_sungrow = bool(entry.data.get(CONF_SUNGROW_HOST))
        is_foxess = bool(entry.data.get(CONF_BATTERY_SYSTEM) == BATTERY_SYSTEM_FOXESS or entry.data.get(CONF_FOXESS_HOST) or entry.data.get(CONF_FOXESS_SERIAL_PORT))
        is_neovolt_pw = bool(_get_neovolt_entry_ids(entry.data, self._hass))
        is_alphaess_pw = bool(entry.data.get(CONF_ALPHAESS_MODBUS_HOST))
        if is_alphaess_pw:
            entry_data = self._hass.data.get(DOMAIN, {}).get(entry.entry_id, {})
            curtailment_state = entry_data.get("alphaess_curtailment_state", "normal")
            grid_export_rule = "never" if curtailment_state == "curtailed" else "battery_ok"
            solar_curtailment_enabled = entry.options.get(
                CONF_BATTERY_CURTAILMENT_ENABLED,
                entry.data.get(CONF_BATTERY_CURTAILMENT_ENABLED, False),
            )
            return web.json_response(
                {
                    "success": True,
                    "backup_reserve": 0,
                    "operation_mode": "self_consumption",
                    "grid_export_rule": grid_export_rule,
                    "grid_charging_enabled": True,
                    "solar_curtailment_enabled": solar_curtailment_enabled,
                    "manual_export_override": entry_data.get("manual_export_override", False),
                    "capabilities": {},
                }
            )
        is_goodwe = bool(entry.data.get(CONF_GOODWE_HOST))
        if is_goodwe:
            # Return current export rule derived from curtailment state
            entry_data = self._hass.data.get(DOMAIN, {}).get(entry.entry_id, {})
            curtailment_state = entry_data.get("goodwe_curtailment_state", "normal")
            grid_export_rule = "never" if curtailment_state == "curtailed" else "battery_ok"
            solar_curtailment_enabled = entry.options.get(
                CONF_BATTERY_CURTAILMENT_ENABLED,
                entry.data.get(CONF_BATTERY_CURTAILMENT_ENABLED, False),
            )
            return web.json_response(
                {
                    "success": True,
                    "backup_reserve": 0,
                    "operation_mode": "self_consumption",
                    "grid_export_rule": grid_export_rule,
                    "grid_charging_enabled": True,
                    "solar_curtailment_enabled": solar_curtailment_enabled,
                    "manual_export_override": entry_data.get("manual_export_override", False),
                    "capabilities": {},
                }
            )
        if is_foxess:
            _LOGGER.info("Powerwall settings not available for FoxESS battery systems")
            return web.json_response(
                {
                    "success": False,
                    "error": "Powerwall settings are not available for FoxESS battery systems",
                    "reason": "foxess_not_supported"
                },
                status=200
            )
        if is_neovolt_pw:
            _LOGGER.info("Powerwall settings not available for Neovolt battery systems")
            return web.json_response(
                {
                    "success": False,
                    "error": "Powerwall settings are not available for Neovolt battery systems",
                    "reason": "neovolt_not_supported",
                    "battery_system": BATTERY_SYSTEM_NEOVOLT,
                },
                status=200
            )
        if is_sigenergy:
            _LOGGER.info("Powerwall settings not available for Sigenergy battery systems")
            return web.json_response(
                {
                    "success": False,
                    "error": "Powerwall settings are not available for Sigenergy battery systems",
                    "reason": "sigenergy_not_supported"
                },
                status=200
            )
        if is_sungrow:
            _LOGGER.info("Powerwall settings not available for Sungrow battery systems")
            return web.json_response(
                {
                    "success": False,
                    "error": "Powerwall settings are not available for Sungrow battery systems",
                    "reason": "sungrow_not_supported"
                },
                status=200
            )

        try:
            current_token, provider = get_tesla_api_token(self._hass, entry)
            site_id = entry.data.get(CONF_TESLA_ENERGY_SITE_ID)

            if not site_id or not current_token:
                return web.json_response(
                    {"success": False, "error": "Missing Tesla site ID or token"},
                    status=503
                )

            session = async_get_clientsession(self._hass)
            headers = {
                "Authorization": f"Bearer {current_token}",
                "Content-Type": "application/json",
            }
            api_base = get_tesla_api_base_url(provider, entry.data.get(CONF_FLEET_API_BASE_URL))

            # Fetch site info
            async with session.get(
                f"{api_base}/api/1/energy_sites/{site_id}/site_info",
                headers=headers,
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status != 200:
                    text = await response.text()
                    _LOGGER.error(f"Failed to get site info: {response.status} - {text}")
                    return web.json_response(
                        {"success": False, "error": f"Failed to get site info: {response.status}"},
                        status=500
                    )
                data = await response.json()
                site_info = data.get("response", {})

            # Extract settings from site_info
            backup_reserve = site_info.get("backup_reserve_percent", 20)
            operation_mode = site_info.get("default_real_mode", "autonomous")

            # Get grid settings from components
            components = site_info.get("components", {})
            # Try components first, then site_info
            api_export_rule = components.get("customer_preferred_export_rule") or site_info.get("customer_preferred_export_rule")
            disallow_charge = components.get("disallow_charge_from_grid_with_solar_installed", False)

            # For VPP users, the API doesn't return customer_preferred_export_rule
            # Use non_export_configured to derive the value, or default to battery_ok
            if api_export_rule is None:
                non_export = components.get("non_export_configured", False)
                api_export_rule = "never" if non_export else "battery_ok"

            # Check if solar curtailment is enabled - if so, use server's target rule
            # (more accurate than stale Tesla API values)
            solar_curtailment_enabled = entry.options.get(
                CONF_BATTERY_CURTAILMENT_ENABLED,
                entry.data.get(CONF_BATTERY_CURTAILMENT_ENABLED, False)
            )

            if solar_curtailment_enabled:
                # Use cached rule (what server is targeting) if available
                entry_data = self._hass.data.get(DOMAIN, {}).get(entry.entry_id, {})
                cached_rule = entry_data.get("cached_export_rule")
                if cached_rule:
                    grid_export_rule = cached_rule
                    _LOGGER.debug(f"Using server's target export rule '{cached_rule}' (API reported '{api_export_rule}')")
                else:
                    grid_export_rule = api_export_rule
            else:
                grid_export_rule = api_export_rule

            # Check if manual export override is active
            entry_data = self._hass.data.get(DOMAIN, {}).get(entry.entry_id, {})
            manual_export_override = entry_data.get("manual_export_override", False)

            # Include capability flags and current state for new energy-site
            # controls (storm watch, off-grid EV reserve, VPP programs). These
            # let the mobile app render the right controls for each site.
            tesla_capabilities = entry_data.get("tesla_capabilities", {}) if entry_data else {}
            tesla_coord = entry_data.get("tesla_coordinator") if entry_data else None
            storm_watch_enabled = None
            off_grid_ev_reserve = None
            if tesla_coord is not None:
                storm_watch_enabled = getattr(tesla_coord, "_storm_mode_enabled", None)
                off_grid_ev_reserve = getattr(tesla_coord, "_off_grid_reserve_percent", None)

            result = {
                "success": True,
                "backup_reserve": backup_reserve,
                "operation_mode": operation_mode,
                "grid_export_rule": grid_export_rule,
                "grid_charging_enabled": not disallow_charge,
                "solar_curtailment_enabled": solar_curtailment_enabled,
                "manual_export_override": manual_export_override,
                "capabilities": {
                    "storm_mode": bool(tesla_capabilities.get("storm_mode", False)),
                    "off_grid_vehicle_charging_reserve": bool(
                        tesla_capabilities.get("off_grid_vehicle_charging_reserve", False)
                    ),
                    "vpp_programs": bool(tesla_capabilities.get("vpp_programs", False)),
                },
                "storm_watch_enabled": storm_watch_enabled,
                "off_grid_ev_reserve_percent": off_grid_ev_reserve,
                "site_country": entry_data.get("tesla_site_country") if entry_data else None,
            }

            _LOGGER.info(f"✅ Powerwall settings: reserve={backup_reserve}%, mode={operation_mode}, export={grid_export_rule}, manual_override={manual_export_override}")
            return web.json_response(result)

        except Exception as e:
            _LOGGER.error(f"Error fetching Powerwall settings: {e}", exc_info=True)
            return web.json_response(
                {"success": False, "error": str(e)},
                status=500
            )


class PowerwallTypeView(HomeAssistantView):
    """HTTP view to get Powerwall type (PW2/PW3) for mobile app Settings."""

    url = "/api/power_sync/powerwall_type"
    name = "api:power_sync:powerwall_type"
    requires_auth = True

    def __init__(self, hass: HomeAssistant):
        """Initialize the view."""
        self._hass = hass

    async def get(self, request: web.Request) -> web.Response:
        """Handle GET request for Powerwall type."""
        _LOGGER.info("🔋 Powerwall type HTTP request")

        # Find the power_sync entry and get token/site_id
        entry = None
        for config_entry in self._hass.config_entries.async_entries(DOMAIN):
            entry = config_entry
            break

        if not entry:
            return web.json_response(
                {"success": False, "error": "PowerSync not configured"},
                status=503
            )

        try:
            current_token, provider = get_tesla_api_token(self._hass, entry)
            site_id = entry.data.get(CONF_TESLA_ENERGY_SITE_ID)

            if not site_id or not current_token:
                return web.json_response(
                    {"success": False, "error": "Missing Tesla site ID or token"},
                    status=503
                )

            session = async_get_clientsession(self._hass)
            headers = {
                "Authorization": f"Bearer {current_token}",
                "Content-Type": "application/json",
            }
            api_base = get_tesla_api_base_url(provider, entry.data.get(CONF_FLEET_API_BASE_URL))

            # Fetch site info
            async with session.get(
                f"{api_base}/api/1/energy_sites/{site_id}/site_info",
                headers=headers,
                timeout=aiohttp.ClientTimeout(total=30),
            ) as response:
                if response.status != 200:
                    text = await response.text()
                    _LOGGER.error(f"Failed to get site info: {response.status} - {text}")
                    return web.json_response(
                        {"success": False, "error": f"Failed to get site info: {response.status}"},
                        status=500
                    )
                data = await response.json()
                site_info = data.get("response", {})

            # Extract gateway info - gateways array contains part_name
            components = site_info.get("components", {})
            gateways = components.get("gateways", [])
            if not gateways:
                # Try top-level gateways
                gateways = site_info.get("gateways", [])

            powerwall_type = "unknown"
            part_name = None

            if gateways and len(gateways) > 0:
                gateway = gateways[0]  # Primary gateway
                part_name = gateway.get("part_name", "")

                # Detect type from part_name
                if "Powerwall 3" in part_name:
                    powerwall_type = "PW3"
                elif "Powerwall 2" in part_name or "Powerwall+" in part_name:
                    powerwall_type = "PW2"
                elif "Powerwall" in part_name:
                    # Generic Powerwall, try to determine from part_number
                    part_number = gateway.get("part_number", "")
                    if part_number.startswith("170"):  # PW3 part numbers start with 170
                        powerwall_type = "PW3"
                    else:
                        powerwall_type = "PW2"  # Default to PW2 for older units

            _LOGGER.info(f"✅ Powerwall type: {powerwall_type} (part_name: {part_name})")

            return web.json_response({
                "success": True,
                "powerwall_type": powerwall_type,
                "part_name": part_name,
                "gateway_count": len(gateways),
            })

        except Exception as e:
            _LOGGER.error(f"Error fetching Powerwall type: {e}", exc_info=True)
            return web.json_response(
                {"success": False, "error": str(e)},
                status=500
            )


def _find_first_power_sync_entry(hass: HomeAssistant):
    for config_entry in hass.config_entries.async_entries(DOMAIN):
        return config_entry
    return None


def _get_tesla_coord_for_view(hass: HomeAssistant):
    """Return (entry, tesla_coordinator) or (entry, None) for HTTP views."""
    entry = _find_first_power_sync_entry(hass)
    if not entry:
        return None, None
    entry_data = hass.data.get(DOMAIN, {}).get(entry.entry_id, {})
    return entry, entry_data.get("tesla_coordinator")


class StormWatchView(HomeAssistantView):
    """GET/POST Tesla Storm Watch enabled state."""

    url = "/api/power_sync/tesla/storm_watch"
    name = "api:power_sync:tesla:storm_watch"
    requires_auth = True

    def __init__(self, hass: HomeAssistant):
        self._hass = hass

    async def get(self, request: web.Request) -> web.Response:
        entry, coord = _get_tesla_coord_for_view(self._hass)
        if coord is None:
            return web.json_response({"success": False, "error": "Tesla not configured"}, status=503)
        if not coord.tesla_capabilities.get("storm_mode", True):
            return web.json_response({
                "success": False,
                "supported": False,
                "error": "Storm Watch is not available for this site",
            }, status=200)
        status = await coord.async_get_storm_watch_status()
        return web.json_response({
            "success": True,
            "supported": True,
            "enabled": coord._storm_mode_enabled,
            "raw": status,
        })

    async def post(self, request: web.Request) -> web.Response:
        try:
            payload = await request.json()
        except Exception:
            return web.json_response({"success": False, "error": "Invalid JSON"}, status=400)
        enabled = payload.get("enabled")
        if enabled is None:
            return web.json_response({"success": False, "error": "Missing 'enabled'"}, status=400)

        entry, coord = _get_tesla_coord_for_view(self._hass)
        if coord is None:
            return web.json_response({"success": False, "error": "Tesla not configured"}, status=503)
        if not coord.tesla_capabilities.get("storm_mode", True):
            return web.json_response({
                "success": False, "error": "Storm Watch not supported for this site",
            }, status=400)

        ok = await coord.async_set_storm_watch(bool(enabled))
        return web.json_response({
            "success": ok,
            "enabled": coord._storm_mode_enabled,
        }, status=200 if ok else 500)


class OffGridEvReserveView(HomeAssistantView):
    """GET/POST off-grid vehicle charging reserve percent."""

    url = "/api/power_sync/tesla/off_grid_ev_reserve"
    name = "api:power_sync:tesla:off_grid_ev_reserve"
    requires_auth = True

    def __init__(self, hass: HomeAssistant):
        self._hass = hass

    async def get(self, request: web.Request) -> web.Response:
        entry, coord = _get_tesla_coord_for_view(self._hass)
        if coord is None:
            return web.json_response({"success": False, "error": "Tesla not configured"}, status=503)
        if not coord.tesla_capabilities.get("off_grid_vehicle_charging_reserve", True):
            return web.json_response({
                "success": False,
                "supported": False,
                "error": "Off-grid EV reserve not available for this site",
            }, status=200)
        return web.json_response({
            "success": True,
            "supported": True,
            "percent": coord._off_grid_reserve_percent,
        })

    async def post(self, request: web.Request) -> web.Response:
        try:
            payload = await request.json()
        except Exception:
            return web.json_response({"success": False, "error": "Invalid JSON"}, status=400)
        percent = payload.get("percent")
        try:
            percent = int(percent)
        except (ValueError, TypeError):
            return web.json_response({"success": False, "error": "Invalid 'percent'"}, status=400)
        if percent < 0 or percent > 100:
            return web.json_response({"success": False, "error": "percent must be 0-100"}, status=400)

        entry, coord = _get_tesla_coord_for_view(self._hass)
        if coord is None:
            return web.json_response({"success": False, "error": "Tesla not configured"}, status=503)
        if not coord.tesla_capabilities.get("off_grid_vehicle_charging_reserve", True):
            return web.json_response({
                "success": False, "error": "Not supported for this site",
            }, status=400)

        ok = await coord.async_set_off_grid_ev_reserve(percent)
        return web.json_response({
            "success": ok,
            "percent": coord._off_grid_reserve_percent,
        }, status=200 if ok else 500)


class VppProgramsView(HomeAssistantView):
    """GET VPP program list / POST enroll or unenroll."""

    url = "/api/power_sync/tesla/vpp_programs"
    name = "api:power_sync:tesla:vpp_programs"
    requires_auth = True

    def __init__(self, hass: HomeAssistant):
        self._hass = hass

    async def get(self, request: web.Request) -> web.Response:
        entry, coord = _get_tesla_coord_for_view(self._hass)
        if coord is None:
            return web.json_response({"success": False, "error": "Tesla not configured"}, status=503)
        if not coord.tesla_capabilities.get("vpp_programs", True):
            return web.json_response({
                "success": False,
                "supported": False,
                "programs": [],
                "error": "VPP programs not available for this site",
            }, status=200)
        force = request.query.get("refresh", "").lower() in ("1", "true", "yes")
        programs = await coord.async_get_vpp_programs(force_refresh=force)
        return web.json_response({
            "success": True,
            "supported": True,
            "programs": programs,
        })

    async def post(self, request: web.Request) -> web.Response:
        try:
            payload = await request.json()
        except Exception:
            return web.json_response({"success": False, "error": "Invalid JSON"}, status=400)
        program_id = payload.get("program_id")
        enrolled = payload.get("enrolled")
        if not program_id or enrolled is None:
            return web.json_response({
                "success": False, "error": "Missing 'program_id' or 'enrolled'",
            }, status=400)

        entry, coord = _get_tesla_coord_for_view(self._hass)
        if coord is None:
            return web.json_response({"success": False, "error": "Tesla not configured"}, status=503)
        if not coord.tesla_capabilities.get("vpp_programs", True):
            return web.json_response({
                "success": False, "error": "VPP programs not supported",
            }, status=400)

        ok = await coord.async_set_vpp_enrollment(str(program_id), bool(enrolled))
        programs = await coord.async_get_vpp_programs(force_refresh=True) if ok else []
        return web.json_response({
            "success": ok,
            "programs": programs,
        }, status=200 if ok else 500)


class BatteryHealthView(HomeAssistantView):
    """HTTP view for battery health data.

    GET: Returns stored battery health from last TEDAPI scan
    POST: Accepts battery health scan data from mobile app
    """

    url = "/api/power_sync/battery_health"
    name = "api:power_sync:battery_health"
    requires_auth = True

    def __init__(self, hass: HomeAssistant):
        """Initialize the view."""
        self._hass = hass

    async def _sync_live_battery_health_to_sensor(
        self,
        entry,
        payload: dict[str, Any],
        *,
        persist: bool = True,
    ) -> None:
        """Mirror live Tesla battery-health payloads into the HA sensor state."""
        if not payload or not payload.get("available"):
            return

        entry_data = self._hass.data[DOMAIN][entry.entry_id]
        current = entry_data.get("battery_health") or {}
        if current and not _battery_health_payload_is_newer(
            payload.get("last_scan"),
            current.get("scanned_at"),
        ):
            return

        health_percent = payload.get("health_percent")
        battery_health_data = {
            "original_capacity_wh": payload.get("original_capacity_wh"),
            "current_capacity_wh": payload.get("current_capacity_wh"),
            "degradation_percent": (
                round(100 - float(health_percent), 1)
                if health_percent is not None
                else None
            ),
            "battery_count": payload.get("battery_count", 1),
            "scanned_at": payload.get("last_scan", dt_util.now().isoformat()),
            "source": payload.get("source", "ha_local_tedapi"),
        }

        if payload.get("individual_batteries"):
            battery_health_data["individual_batteries"] = payload.get("individual_batteries")
        if payload.get("site"):
            battery_health_data["site"] = payload.get("site")
        if payload.get("raw_vitals") is not None:
            battery_health_data["raw_vitals"] = payload.get("raw_vitals")

        entry_data["battery_health"] = battery_health_data

        store = entry_data.get("store")
        if persist and store:
            stored_data = await store.async_load() or {}
            stored_data["battery_health"] = battery_health_data
            await store.async_save(stored_data)

        from homeassistant.helpers.dispatcher import async_dispatcher_send
        async_dispatcher_send(
            self._hass,
            f"{DOMAIN}_battery_health_update_{entry.entry_id}",
            battery_health_data,
        )

    def _get_coordinator_bms(self, entry) -> tuple[str, dict] | None:
        """Extract BMS telemetry from the active coordinator for non-Tesla systems.

        Returns (brand, bms_dict) with normalised snake_case keys, or None.
        """
        entry_data = self._hass.data.get(DOMAIN, {}).get(entry.entry_id, {})

        brand_map = {
            "sungrow_coordinator": "sungrow",
            "sigenergy_coordinator": "sigenergy",
            "goodwe_coordinator": "goodwe",
            "alphaess_coordinator": "alphaess",
            "foxess_coordinator": "foxess",
            "fronius_reserva_coordinator": "fronius_reserva",
            "neovolt_coordinator": "neovolt",
            "solaredge_coordinator": "solaredge",
            "anker_solix_coordinator": "anker_solix",
        }

        for coord_key, brand in brand_map.items():
            coord = entry_data.get(coord_key)
            if not coord or not coord.data:
                continue

            d = coord.data
            bms: dict = {}

            if brand == "sungrow":
                soh_percent = None
                if (v := d.get("battery_soh")) is not None:
                    soh_percent = round(float(v), 1)
                    bms["soh_percent"] = soh_percent
                rated_capacity_kwh = d.get("battery_capacity_kwh")
                if rated_capacity_kwh is None:
                    rated_capacity_kwh = _configured_battery_capacity_kwh(entry)
                if rated_capacity_kwh is not None:
                    rated_capacity_kwh = round(float(rated_capacity_kwh), 2)
                    bms["rated_capacity_kwh"] = rated_capacity_kwh
                    current_capacity_kwh = _current_capacity_from_soh_kwh(
                        rated_capacity_kwh,
                        soh_percent,
                    )
                    if current_capacity_kwh is not None:
                        bms["current_capacity_kwh"] = current_capacity_kwh
                if (v := d.get("battery_temp")) is not None: bms["temperature_c"] = round(float(v), 1)
                if (v := d.get("inverter_temperature")) is not None: bms["inverter_temperature_c"] = round(float(v), 1)
                if (v := d.get("battery_voltage")) is not None: bms["voltage_v"] = round(float(v), 1)
                if (v := d.get("battery_current")) is not None: bms["current_a"] = round(float(v), 1)
                if (v := d.get("battery_level")) is not None: bms["soc_percent"] = round(float(v), 1)
                if (v := d.get("min_soc")) is not None: bms["min_soc_percent"] = round(float(v), 1)
                if (v := d.get("max_soc")) is not None: bms["max_soc_percent"] = round(float(v), 1)
                if (v := d.get("battery_max_charge_power_w")) is not None: bms["max_charge_power_w"] = int(v)
                if (v := d.get("battery_max_discharge_power_w")) is not None: bms["max_discharge_power_w"] = int(v)

            elif brand == "sigenergy":
                if (v := d.get("battery_soh")) is not None: bms["soh_percent"] = round(float(v), 1)
                if (v := d.get("battery_capacity_kwh")) is not None: bms["rated_capacity_kwh"] = round(float(v), 2)
                if (v := d.get("battery_level")) is not None: bms["soc_percent"] = round(float(v), 1)
                if (v := d.get("battery_max_charge_power_w")) is not None: bms["max_charge_power_w"] = int(v)
                if (v := d.get("battery_max_discharge_power_w")) is not None: bms["max_discharge_power_w"] = int(v)

            elif brand == "goodwe":
                if (v := d.get("battery_soh")) is not None: bms["soh_percent"] = round(float(v), 1)
                if (v := d.get("battery_temperature")) is not None: bms["temperature_c"] = round(float(v), 1)
                if (v := d.get("battery_max_charge_power_w")) is not None: bms["max_charge_power_w"] = int(v)
                if (v := d.get("battery_max_discharge_power_w")) is not None: bms["max_discharge_power_w"] = int(v)
                if (v := d.get("model_name")) is not None: bms["model_name"] = str(v)
                if (v := d.get("serial_number")) is not None: bms["serial_number"] = str(v)

            elif brand == "alphaess":
                if (v := d.get("battery_soh")) is not None: bms["soh_percent"] = round(float(v), 1)
                if (v := d.get("battery_capacity_kwh")) is not None: bms["rated_capacity_kwh"] = round(float(v), 2)
                if (v := d.get("battery_level")) is not None: bms["soc_percent"] = round(float(v), 1)
                if (v := d.get("battery_max_charge_power_w")) is not None: bms["max_charge_power_w"] = int(v)
                if (v := d.get("battery_max_discharge_power_w")) is not None: bms["max_discharge_power_w"] = int(v)

            elif brand == "neovolt":
                if (v := d.get("battery_soh")) is not None: bms["soh_percent"] = round(float(v), 1)
                if (v := d.get("battery_capacity_kwh")) is not None: bms["rated_capacity_kwh"] = round(float(v), 2)
                if (v := d.get("battery_level")) is not None: bms["soc_percent"] = round(float(v), 1)
                if (v := d.get("battery_max_charge_power_w")) is not None: bms["max_charge_power_w"] = int(v)
                if (v := d.get("battery_max_discharge_power_w")) is not None: bms["max_discharge_power_w"] = int(v)

            elif brand == "anker_solix":
                if (v := d.get("battery_capacity_kwh")) is not None: bms["rated_capacity_kwh"] = round(float(v), 2)
                if (v := d.get("battery_level")) is not None: bms["soc_percent"] = round(float(v), 1)
                if (v := d.get("battery_max_charge_power_w")) is not None: bms["max_charge_power_w"] = int(v)
                if (v := d.get("battery_max_discharge_power_w")) is not None: bms["max_discharge_power_w"] = int(v)
                if (v := d.get("control_path")) is not None: bms["control_path"] = str(v)

            elif brand == "fronius_reserva":
                if (v := d.get("battery_temperature")) is not None: bms["temperature_c"] = round(float(v), 1)
                if (v := d.get("battery_capacity_kwh")) is not None: bms["rated_capacity_kwh"] = round(float(v), 2)
                if (v := d.get("battery_level")) is not None: bms["soc_percent"] = round(float(v), 1)
                if (v := d.get("min_soc")) is not None: bms["min_soc_percent"] = round(float(v), 1)
                if (v := d.get("battery_max_charge_power_w")) is not None: bms["max_charge_power_w"] = int(v)
                if (v := d.get("battery_max_discharge_power_w")) is not None: bms["max_discharge_power_w"] = int(v)

            elif brand == "foxess":
                if (v := d.get("battery_soh")) is not None: bms["soh_percent"] = round(float(v), 1)
                if (v := d.get("battery_temperature")) is not None: bms["temperature_c"] = round(float(v), 1)
                if (v := d.get("battery_level")) is not None: bms["soc_percent"] = round(float(v), 1)
                if (v := d.get("battery_voltage_v")) is not None: bms["voltage_v"] = round(float(v), 1)
                if (v := d.get("nominal_energy_kwh")) is not None: bms["rated_capacity_kwh"] = round(float(v), 2)
                if (v := d.get("min_soc")) is not None: bms["min_soc_percent"] = round(float(v), 1)
                if (v := d.get("max_charge_current_a")) is not None: bms["max_charge_current_a"] = round(float(v), 1)
                if (v := d.get("max_discharge_current_a")) is not None: bms["max_discharge_current_a"] = round(float(v), 1)
                if (v := d.get("battery_max_charge_power_w")) is not None: bms["max_charge_power_w"] = int(v)
                if (v := d.get("battery_max_discharge_power_w")) is not None: bms["max_discharge_power_w"] = int(v)

            if bms:
                return brand, bms

        return None

    async def _try_fleet_api_bms_fetch(self, entry) -> dict | None:
        """Attempt a signed DeviceControllerQuery via Fleet API and return a response dict.

        Requires RSA key + DIN from Powerwall pairing and a valid Fleet API OAuth token.
        Returns None on any missing prerequisite or failure — callers fall through gracefully.
        """
        import base64 as _b64
        import aiohttp as _aio

        from .const import (
            CONF_POWERWALL_LOCAL_PRIVATE_KEY,
            CONF_POWERWALL_LOCAL_DIN,
            CONF_POWERWALL_LOCAL_IP,
            CONF_POWERWALL_LOCAL_ENERGY_SITE_ID,
        )
        from .powerwall_local.views import _get_fleet_api_context
        from .powerwall_local.fleet_api_bms import (
            build_device_controller_query_envelope,
            build_signed_routable_message,
            parse_device_controller_response,
        )
        from .powerwall_local.bms_health import (
            assign_pack_roles_from_battery_blocks,
            has_pw3_stack,
            known_expansion_dins_from_gateway_config,
            reconcile_pack_remaining_with_aggregate,
            serial_from_din,
            trim_excess_pw3_follower_placeholders,
        )
        from .powerwall_local.client import is_loopback_host

        private_key_pem = entry.data.get(CONF_POWERWALL_LOCAL_PRIVATE_KEY)
        din = entry.data.get(CONF_POWERWALL_LOCAL_DIN)
        if not private_key_pem or not din:
            return None

        fleet_token, fleet_base, fleet_site_id = _get_fleet_api_context(self._hass, entry)
        # Don't bail yet — local gateway path can succeed without Fleet API credentials.

        # Run RSA key loading + signing in an executor to avoid blocking the event loop.
        try:
            key_bytes = private_key_pem.encode() if isinstance(private_key_pem, str) else private_key_pem
            envelope = build_device_controller_query_envelope(din)

            def _sign_in_thread() -> bytes:
                return build_signed_routable_message(envelope, din, key_bytes, ttl_seconds=300)

            signed = await self._hass.async_add_executor_job(_sign_in_thread)
        except Exception as err:
            _LOGGER.error("fleet_api_bms: signing failed: %s", err)
            return None

        # Try local TEDAPI gateway first — it has direct CAN bus visibility of all
        # connected Powerwall units, so follower BMS signals are non-None here even
        # though the Fleet API relay drops them. Fall back to Fleet API when the
        # gateway is unreachable (e.g. user is away from home).
        data = None
        source = "ha_local_tedapi"
        local_ip = str(entry.data.get(CONF_POWERWALL_LOCAL_IP) or "").strip()
        if local_ip and not is_loopback_host(local_ip):
            try:
                from .powerwall_local.transport import get_insecure_ssl_context
                from .powerwall_local import tedapi_combined_pb2 as _pb2
                ssl_ctx = await get_insecure_ssl_context(self._hass)
                connector = _aio.TCPConnector(ssl=ssl_ctx, limit=2)
                async with _aio.ClientSession(
                    connector=connector,
                    timeout=_aio.ClientTimeout(total=12),
                ) as sess:
                    async with sess.post(
                        f"https://{local_ip}/tedapi/v1r",
                        data=signed,
                        headers={"Content-Type": "application/octet-stream"},
                    ) as resp:
                        if resp.status == 200:
                            raw = await resp.read()
                            resp_msg = _pb2.RoutableMessage()
                            resp_msg.ParseFromString(raw)
                            fault = resp_msg.signed_message_status.message_fault
                            if fault == _pb2.MESSAGEFAULT_ERROR_NONE:
                                local_data = parse_device_controller_response(
                                    resp_msg.protobuf_message_as_bytes
                                )
                                if local_data:
                                    _LOGGER.info("fleet_api_bms: local gateway BMS fetch OK")
                                    data = local_data
                            else:
                                _LOGGER.debug(
                                    "fleet_api_bms: local gateway fault %s",
                                    _pb2.MessageFault_E.Name(fault),
                                )
                        else:
                            body_text = await resp.text()
                            _LOGGER.debug(
                                "fleet_api_bms: local gateway HTTP %d — %s",
                                resp.status, body_text[:200],
                            )
            except Exception as err:
                _LOGGER.debug("fleet_api_bms: local gateway unreachable: %s", err)
        elif local_ip:
            _LOGGER.debug(
                "fleet_api_bms: skipping loopback placeholder gateway host %s",
                local_ip,
            )

        if data is None:
            # Fleet API relay fallback.
            if not fleet_token or not fleet_base or not fleet_site_id:
                _LOGGER.debug("fleet_api_bms: no local gateway and no Fleet API credentials")
                return None
            source = "ha_fleet_api_relay"
            fleet_url = f"{fleet_base}/api/1/energy_sites/{fleet_site_id}/device_command"
            fleet_headers = {
                "Authorization": f"Bearer {fleet_token}",
                "Content-Type": "application/json",
            }
            fleet_payload = {
                "data": {
                    "target_id": din,
                    "routable_message": _b64.b64encode(signed).decode(),
                    "command_timeout_s": 10,
                    "identifier_type": 1,
                }
            }
            try:
                async with _aio.ClientSession() as sess:
                    async with sess.post(
                        fleet_url, json=fleet_payload, headers=fleet_headers,
                        timeout=_aio.ClientTimeout(total=35),
                    ) as resp:
                        if resp.status != 200:
                            body_text = await resp.text()
                            _LOGGER.warning(
                                "fleet_api_bms: HTTP %d — %s", resp.status, body_text[:400]
                            )
                            return None
                        body = await resp.json()
            except Exception as err:
                _LOGGER.error("fleet_api_bms: request error: %s", err)
                return None

            envelope_b64 = (body.get("response") or {}).get("message_envelope_as_bytes")
            if not envelope_b64:
                _LOGGER.warning(
                    "fleet_api_bms: no message_envelope_as_bytes in response: %s",
                    str(body)[:400],
                )
                return None
            try:
                data = parse_device_controller_response(_b64.b64decode(envelope_b64))
            except Exception as err:
                _LOGGER.warning("fleet_api_bms: decode error: %s", err)
                return None
            if data is None:
                _LOGGER.warning("fleet_api_bms: failed to extract text from response envelope")
                return None

        gateway_config = None
        try:
            runtime = self._hass.data.get(DOMAIN, {}).get(entry.entry_id, {})
            local_runtime = runtime.get("powerwall_local") or {}
            local_coordinator = local_runtime.get("coordinator")
            local_snapshot = getattr(local_coordinator, "data", None)
            raw_snapshot = getattr(local_snapshot, "raw", None)
            if isinstance(raw_snapshot, dict) and isinstance(raw_snapshot.get("config"), dict):
                gateway_config = raw_snapshot["config"]
            else:
                local_client = local_runtime.get("client") or getattr(local_coordinator, "client", None)
                local_transport = getattr(local_client, "_transport", None)
                if (
                    local_transport is not None
                    and getattr(local_client, "local_access_enabled", True) is not False
                    and not is_loopback_host(getattr(local_client, "host", None))
                ):
                    gateway_config = await local_transport.read_config(din)
        except Exception as err:
            _LOGGER.debug("fleet_api_bms: config.json read for expansion mapping failed: %s", err)

        # Primary source: control.systemStatus aggregate (matches cloud worker).
        # This is authoritative for the whole site — never override with partial per-pack sums.
        status = ((data.get("control") or {}).get("systemStatus") or {})
        current_wh = status.get("nominalFullPackEnergyWh") or 0
        rem_wh = status.get("nominalEnergyRemainingWh") or 0

        # batteryBlocks: one entry per Powerwall inverter unit (not per battery module).
        # PW3 with 2 expansion packs = 1 batteryBlock entry, 3 PW3BMS entries in msa.
        battery_blocks = (data.get("control") or {}).get("batteryBlocks") or []
        bb_count = len(battery_blocks) if battery_blocks else 1

        # Per-pack BMS breakdown from components.msa.
        # Only PW3BMS components carry BMS_nominalFullPackEnergy; PVS/PVAC/TESYNC etc. have 0.
        all_comps = (data.get("components") or {}).get("msa") or []
        is_pw3_stack = has_pw3_stack(battery_blocks, all_comps, din)
        _LOGGER.debug(
            "fleet_api_bms: batteryBlocks=%d, msa_total=%d entries: %s",
            bb_count, len(all_comps),
            [(c.get("partNumber"), c.get("serialNumber"),
              {s["name"]: s.get("value") for s in (c.get("signals") or [])
               if s["name"] in ("BMS_nominalFullPackEnergy", "BMS_nominalEnergyRemaining")})
             for c in all_comps],
        )
        individual = []
        bms_module_count = 0
        for pack in all_comps:
            sigs = {s["name"]: s.get("value") for s in (pack.get("signals") or [])}
            if "BMS_nominalFullPackEnergy" not in sigs:
                continue  # skip non-BMS components (PVS, PVAC, etc.) — they have no BMS signal key
            bms_module_count += 1
            # BMS_nominalFullPackEnergy is in kWh; convert to Wh for the app.
            pack_full_wh = (sigs.get("BMS_nominalFullPackEnergy") or 0) * 1000
            pack_rem_wh = (sigs.get("BMS_nominalEnergyRemaining") or 0) * 1000
            # Follower PW3 base modules report the BMS signal key but with None values.
            is_follower = (
                is_pw3_stack
                and pack_full_wh == 0
                and sigs.get("BMS_nominalFullPackEnergy") is None
            )
            individual.append({
                "nominalFullPackEnergyWh": pack_full_wh,
                "nominalEnergyRemainingWh": pack_rem_wh,
                "bmsSerialNumber": pack.get("serialNumber") or None,
                "serialNumber": pack.get("serialNumber") or None,
                "role": "unknown",
                "isExpansion": bool(is_pw3_stack and individual and not is_follower),
                "isFollower": is_follower,
            })

        if is_pw3_stack:
            dropped_followers = trim_excess_pw3_follower_placeholders(
                individual,
                battery_blocks,
                din,
            )
            if dropped_followers:
                bms_module_count = max(0, bms_module_count - dropped_followers)
                _LOGGER.warning(
                    "fleet_api_bms: dropping %d excess PW3 follower placeholder(s); "
                    "batteryBlocks report %d physical follower unit(s)",
                    dropped_followers,
                    max(0, len(battery_blocks) - 1),
                )

        # Follower units report None BMS signals — their contribution is inferable from the
        # aggregate systemStatus total minus the sum of leader packs. The serial number comes
        # from batteryBlocks[].din (format: "partNum--serial"). For multiple followers the
        # remaining energy is split evenly among them.
        follower_indices = [
            i for i, p in enumerate(individual)
            if p.get("isFollower") and p.get("nominalFullPackEnergyWh") == 0
        ]
        if is_pw3_stack and follower_indices and current_wh:
            leader_full_wh = sum(
                p["nominalFullPackEnergyWh"] for p in individual if not p.get("isFollower")
            )
            leader_rem_wh = sum(
                p["nominalEnergyRemainingWh"] for p in individual if not p.get("isFollower")
            )
            n_followers = len(follower_indices)
            inferred_full_wh = max(0.0, current_wh - leader_full_wh) / n_followers
            inferred_rem_wh = max(0.0, rem_wh - leader_rem_wh) / n_followers
            follower_dins = [
                block.get("din") for block in battery_blocks
                if block.get("din") and block.get("din") != din
            ]
            for seq, idx in enumerate(follower_indices):
                f_din = follower_dins[seq] if seq < len(follower_dins) else None
                serial = serial_from_din(f_din)
                individual[idx] = {
                    "nominalFullPackEnergyWh": inferred_full_wh,
                    "nominalEnergyRemainingWh": inferred_rem_wh,
                    "bmsSerialNumber": None,
                    "physicalDin": f_din,
                    "serialNumber": serial,
                    "role": "follower",
                    "isExpansion": False,
                    "isFollower": True,
                }
            _LOGGER.debug(
                "fleet_api_bms: inferred follower data: %d unit(s), %.0f Wh each",
                n_followers, inferred_full_wh,
            )

        # Role labelling: PW3 has leader/follower base units plus expansion
        # BMS modules; PW2 has separate Powerwalls and should stay as plain
        # powerwall packs.
        assign_pack_roles_from_battery_blocks(
            individual,
            battery_blocks,
            din,
            all_comps,
            known_expansion_dins_from_gateway_config(gateway_config),
        )

        # Ghost expansion pack filter. Phantom packs (registered slots not physically
        # installed) report:
        #   1. plausible full-capacity values (~13.5–14.5 kWh)
        #   2. NO serialNumber from MSA components
        #   3. near-zero remaining energy regardless of system SOC
        #
        # Real BMS modules satisfy AT LEAST ONE of: have a serialNumber, or report
        # remaining energy that tracks system SOC. The previous filter keyed off
        # (!serialNumber) alone, which mis-dropped real expansion packs whose firmware
        # doesn't populate serialNumber in the MSA components surface (observed on
        # PW3 + 1 expansion sites — current_wh reported only the leader's energy, so
        # the cross-validation kept-sum check passed despite the real expansion being
        # kept). Require BOTH the missing-serial signal AND a near-zero remaining-
        # energy signature before flagging as ghost; cross-validate as before.
        if individual and current_wh > 0:
            GHOST_REMAINING_ABS_WH = 500
            GHOST_REMAINING_FRACTION = 0.05
            ghost_candidates = [
                p for p in individual
                if p.get("isExpansion")
                and not p.get("serialNumber")
                and (
                    p["nominalEnergyRemainingWh"] < GHOST_REMAINING_ABS_WH
                    or (
                        p["nominalFullPackEnergyWh"] > 0
                        and p["nominalEnergyRemainingWh"] / p["nominalFullPackEnergyWh"]
                        < GHOST_REMAINING_FRACTION
                    )
                )
            ]
            if ghost_candidates:
                kept = [p for p in individual if p not in ghost_candidates]
                kept_full_wh = sum(p["nominalFullPackEnergyWh"] for p in kept)
                if kept_full_wh > 0 and abs(current_wh - kept_full_wh) / current_wh < 0.10:
                    ghost_count = len(ghost_candidates)
                    _LOGGER.info(
                        "fleet_api_bms: dropping %d placeholder expansion pack(s) (no serial + near-empty) — "
                        "system %.0f Wh matches real-pack sum %.0f Wh (ratio %.3f); "
                        "expansion slots registered but not physically installed",
                        ghost_count, current_wh, kept_full_wh, kept_full_wh / current_wh,
                    )
                    individual = kept
                    bms_module_count -= ghost_count

        individual = reconcile_pack_remaining_with_aggregate(
            individual,
            rem_wh,
            current_wh,
            logger=_LOGGER,
        )

        # Module count: BMS signal presence is the most accurate count (includes follower packs
        # that report the signal key but have None values). batteryBlocks counts inverter units
        # (one per PW3 stack), not individual battery modules — use it only as a floor.
        batt_count = max(bms_module_count, bb_count) if bms_module_count else bb_count

        # Cross-validate against Tesla's own site_info battery_count. PW3 units each expose
        # two BMS sub-modules in the msa components list, so bms_module_count can be 2× the
        # actual physical Powerwall count. site_info.battery_count is Tesla's authoritative
        # count of physical units — prefer it when the BMS count exceeds it.
        try:
            _coord = (self._hass.data.get(DOMAIN, {}).get(entry.entry_id, {})
                      .get("tesla_coordinator"))
            _site_batt_count = (
                (_coord._site_info_cache or {}).get("battery_count")
                if _coord and hasattr(_coord, "_site_info_cache")
                else None
            )
            if _site_batt_count and batt_count > _site_batt_count:
                _LOGGER.info(
                    "fleet_api_bms: BMS module count (%d) exceeds site battery_count (%d) — "
                    "using site battery_count for rated capacity (PW3 has 2 BMS sub-modules per unit)",
                    batt_count, _site_batt_count,
                )
                batt_count = _site_batt_count
        except Exception:
            pass

        # Rated capacity: 13.5 kWh per physical Powerwall unit.
        original_wh = 13500 * batt_count
        health_percent = round((current_wh / original_wh) * 100, 1) if original_wh > 0 else 0

        bms: dict = {}
        if health_percent: bms["soh_percent"] = health_percent
        if original_wh: bms["rated_capacity_kwh"] = round(original_wh / 1000, 2)
        if current_wh: bms["current_capacity_kwh"] = round(current_wh / 1000, 2)

        response: dict = {
            "success": True,
            "available": True,
            "brand": "tesla",
            "source": source,
            "health_percent": health_percent,
            "original_capacity_wh": original_wh,
            "current_capacity_wh": current_wh,
            "original_capacity_kwh": round(original_wh / 1000, 2),
            "current_capacity_kwh": round(current_wh / 1000, 2),
            "battery_count": batt_count,
            "last_scan": dt_util.now().isoformat(),
            "site": {
                "gateway_din": din,
                "energy_site_id": fleet_site_id or entry.data.get(CONF_POWERWALL_LOCAL_ENERGY_SITE_ID),
            },
        }
        if bms:
            response["bms"] = bms
        if individual:
            response["individual_batteries"] = individual
        if rem_wh:
            response["nominal_energy_remaining_wh"] = rem_wh

        _LOGGER.info(
            "fleet_api_bms: Tesla health %.1f%% (%d Wh / %d Wh), %d module(s), %d batteryBlock(s), %d msa_bms [%s]",
            health_percent, current_wh, original_wh, batt_count, bb_count, len(individual), source,
        )
        return response

    async def _try_fleet_api_solar_strings_fetch(self, entry) -> dict | None:
        """Fetch Powerwall DC string diagnostics via signed TEDAPI queries."""
        import base64 as _b64
        import aiohttp as _aio

        from .const import (
            CONF_POWERWALL_LOCAL_PRIVATE_KEY,
            CONF_POWERWALL_LOCAL_DIN,
            CONF_POWERWALL_LOCAL_IP,
        )
        from .powerwall_local.views import _get_fleet_api_context
        from .powerwall_local.fleet_api_bms import (
            build_device_controller_query_envelope,
            build_pw3_components_query_envelope,
            build_signed_routable_message,
            normalize_legacy_pvac_strings,
            normalize_pw3_components_strings,
            parse_device_controller_response,
        )

        private_key_pem = entry.data.get(CONF_POWERWALL_LOCAL_PRIVATE_KEY)
        din = entry.data.get(CONF_POWERWALL_LOCAL_DIN)
        if not private_key_pem or not din:
            return None

        fleet_token, fleet_base, fleet_site_id = _get_fleet_api_context(self._hass, entry)
        key_bytes = private_key_pem.encode() if isinstance(private_key_pem, str) else private_key_pem

        async def _read_query(envelope_builder, log_label: str) -> tuple[dict | None, str | None]:
            try:
                envelope = envelope_builder(din)

                def _sign_in_thread() -> bytes:
                    return build_signed_routable_message(envelope, din, key_bytes, ttl_seconds=300)

                signed = await self._hass.async_add_executor_job(_sign_in_thread)
            except Exception as err:
                _LOGGER.debug("fleet_api_solar_strings: %s signing failed: %s", log_label, err)
                return None, None

            local_ip = entry.data.get(CONF_POWERWALL_LOCAL_IP)
            if local_ip:
                try:
                    from .powerwall_local.transport import get_insecure_ssl_context
                    from .powerwall_local import tedapi_combined_pb2 as _pb2
                    ssl_ctx = await get_insecure_ssl_context(self._hass)
                    connector = _aio.TCPConnector(ssl=ssl_ctx, limit=2)
                    async with _aio.ClientSession(
                        connector=connector,
                        timeout=_aio.ClientTimeout(total=12),
                    ) as sess:
                        async with sess.post(
                            f"https://{local_ip}/tedapi/v1r",
                            data=signed,
                            headers={"Content-Type": "application/octet-stream"},
                        ) as resp:
                            if resp.status == 200:
                                raw = await resp.read()
                                resp_msg = _pb2.RoutableMessage()
                                resp_msg.ParseFromString(raw)
                                fault = resp_msg.signed_message_status.message_fault
                                if fault == _pb2.MESSAGEFAULT_ERROR_NONE:
                                    data = parse_device_controller_response(
                                        resp_msg.protobuf_message_as_bytes
                                    )
                                    if data:
                                        return data, "ha_local_tedapi"
                                else:
                                    _LOGGER.debug(
                                        "fleet_api_solar_strings: local %s fault %s",
                                        log_label,
                                        _pb2.MessageFault_E.Name(fault),
                                    )
                            else:
                                body_text = await resp.text()
                                _LOGGER.debug(
                                    "fleet_api_solar_strings: local %s HTTP %d - %s",
                                    log_label, resp.status, body_text[:200],
                                )
                except Exception as err:
                    _LOGGER.debug("fleet_api_solar_strings: local %s unreachable: %s", log_label, err)

            if not fleet_token or not fleet_base or not fleet_site_id:
                return None, None

            fleet_url = f"{fleet_base}/api/1/energy_sites/{fleet_site_id}/device_command"
            fleet_headers = {
                "Authorization": f"Bearer {fleet_token}",
                "Content-Type": "application/json",
            }
            fleet_payload = {
                "data": {
                    "target_id": din,
                    "routable_message": _b64.b64encode(signed).decode(),
                    "command_timeout_s": 10,
                    "identifier_type": 1,
                }
            }
            try:
                async with _aio.ClientSession() as sess:
                    async with sess.post(
                        fleet_url,
                        json=fleet_payload,
                        headers=fleet_headers,
                        timeout=_aio.ClientTimeout(total=35),
                    ) as resp:
                        if resp.status != 200:
                            body_text = await resp.text()
                            _LOGGER.debug(
                                "fleet_api_solar_strings: %s HTTP %d - %s",
                                log_label, resp.status, body_text[:400],
                            )
                            return None, None
                        body = await resp.json()
            except Exception as err:
                _LOGGER.debug("fleet_api_solar_strings: %s request error: %s", log_label, err)
                return None, None

            envelope_b64 = (body.get("response") or {}).get("message_envelope_as_bytes")
            if not envelope_b64:
                return None, None
            try:
                data = parse_device_controller_response(_b64.b64decode(envelope_b64))
            except Exception as err:
                _LOGGER.debug("fleet_api_solar_strings: %s decode error: %s", log_label, err)
                return None, None
            return data, "ha_fleet_api_relay" if data else None

        data, transport_source = await _read_query(
            build_pw3_components_query_envelope,
            "pw3_components",
        )
        saw_response = data is not None
        last_transport_source = transport_source if data is not None else None
        diagnostics = normalize_pw3_components_strings(data) if data else None

        if diagnostics is None:
            data, transport_source = await _read_query(
                build_device_controller_query_envelope,
                "legacy_pvac",
            )
            saw_response = saw_response or data is not None
            if data is not None:
                last_transport_source = transport_source
            diagnostics = normalize_legacy_pvac_strings(data) if data else None

        if diagnostics is None:
            if saw_response:
                return {
                    "success": True,
                    "available": False,
                    "brand": "tesla",
                    "source": None,
                    "transport_source": last_transport_source,
                    "strings": [],
                    "groups": [],
                    "last_scan": dt_util.now().isoformat(),
                    "site": {
                        "gateway_din": din,
                        "energy_site_id": fleet_site_id,
                    },
                }
            return None

        response = {
            "success": True,
            "available": True,
            "brand": "tesla",
            "transport_source": transport_source,
            "last_scan": dt_util.now().isoformat(),
            "site": {
                "gateway_din": din,
                "energy_site_id": fleet_site_id,
            },
            **diagnostics,
        }
        _LOGGER.debug(
            "fleet_api_solar_strings: fetched %d string(s), %d group(s) via %s/%s",
            len(response.get("strings") or []),
            len(response.get("groups") or []),
            response.get("source"),
            transport_source,
        )
        return response

    async def get(self, request: web.Request) -> web.Response:
        """Handle GET request - return stored battery health data."""
        _LOGGER.info("🔋 Battery health HTTP request")

        # Find the power_sync entry
        entry = None
        for config_entry in self._hass.config_entries.async_entries(DOMAIN):
            entry = config_entry
            break

        if not entry:
            return web.json_response(
                {"success": False, "error": "PowerSync not configured"},
                status=503
            )

        try:
            import time as _t

            domain_data = self._hass.data.get(DOMAIN, {})
            entry_data = domain_data.get(entry.entry_id, {})
            battery_system = entry.data.get(CONF_BATTERY_SYSTEM, "tesla")

            # Tesla: always go via Fleet API (with 1-hour cache). Never use stale
            # WiFi-scan data from storage — the Fleet API path supersedes it.
            if battery_system == "tesla":
                refresh = request.query.get("refresh") == "1"
                cache = entry_data.get("battery_health_cloud")
                now = _t.monotonic()
                if not refresh and cache and cache.get("expires_at", 0) > now:
                    await self._sync_live_battery_health_to_sensor(entry, cache["value"])
                    return web.json_response(cache["value"])
                fleet_result = await self._try_fleet_api_bms_fetch(entry)
                if fleet_result:
                    entry_data["battery_health_cloud"] = {
                        "value": fleet_result,
                        "expires_at": now + 3600,
                    }
                    await self._sync_live_battery_health_to_sensor(entry, fleet_result)
                    return web.json_response(fleet_result)
                return web.json_response({
                    "success": True,
                    "available": False,
                    "brand": "tesla",
                    "message": (
                        "Powerwall not paired. Complete pairing in Local Control "
                        "to enable Battery Health."
                    ),
                })

            # Non-Tesla: live BMS telemetry from the modbus coordinator
            bms_result = self._get_coordinator_bms(entry)
            if bms_result:
                brand, bms = bms_result
                return web.json_response({
                    "success": True,
                    "available": True,
                    "brand": brand,
                    "source": "inverter_modbus",
                    "bms": bms,
                })

            return web.json_response({
                "success": True,
                "available": False,
                "message": "No battery health data available.",
            })

        except Exception as e:
            _LOGGER.error(f"Error fetching battery health: {e}", exc_info=True)
            return web.json_response(
                {"success": False, "error": str(e)},
                status=500
            )

    async def post(self, request: web.Request) -> web.Response:
        """Handle POST request - receive battery health scan data from mobile app."""
        _LOGGER.info("🔋 Battery health scan data received via HTTP")

        # Find the power_sync entry
        entry = None
        for config_entry in self._hass.config_entries.async_entries(DOMAIN):
            entry = config_entry
            break

        if not entry:
            return web.json_response(
                {"success": False, "error": "PowerSync not configured"},
                status=503
            )

        try:
            data = await request.json()

            original_capacity_wh = data.get("original_capacity_wh")
            current_capacity_wh = data.get("current_capacity_wh")
            degradation_percent = data.get("degradation_percent")
            battery_count = data.get("battery_count", 1)
            scanned_at = data.get("scanned_at", dt_util.now().isoformat())
            individual_batteries = data.get("individual_batteries")
            # Extended fields (cloud RSA path provides richer metadata)
            source = data.get("source") or "mobile_app"
            gateway_din = data.get("gateway_din")
            energy_site_id = data.get("energy_site_id")
            site_name = data.get("site_name")
            raw_vitals = data.get("raw_vitals")

            # Validate required fields
            if original_capacity_wh is None or current_capacity_wh is None or degradation_percent is None:
                return web.json_response(
                    {"success": False, "error": "Missing required fields: original_capacity_wh, current_capacity_wh, degradation_percent"},
                    status=400
                )

            health_percent = round((current_capacity_wh / original_capacity_wh) * 100, 1) if original_capacity_wh > 0 else 0

            _LOGGER.info(
                f"🔋 Battery health received ({source}): {health_percent}% health ({current_capacity_wh}Wh / {original_capacity_wh}Wh, {battery_count} units)"
            )

            # Build battery health data
            battery_health_data = {
                "original_capacity_wh": original_capacity_wh,
                "current_capacity_wh": current_capacity_wh,
                "degradation_percent": degradation_percent,
                "battery_count": battery_count,
                "scanned_at": scanned_at,
                "source": source,
            }

            if individual_batteries:
                battery_health_data["individual_batteries"] = individual_batteries
                _LOGGER.info(f"  Individual batteries: {len(individual_batteries)} units")

            site_info: dict = {}
            if gateway_din: site_info["gateway_din"] = gateway_din
            if energy_site_id is not None: site_info["energy_site_id"] = energy_site_id
            if site_name: site_info["site_name"] = site_name
            if site_info:
                battery_health_data["site"] = site_info
                _LOGGER.info(f"  Site: {site_info}")

            if raw_vitals is not None:
                battery_health_data["raw_vitals"] = raw_vitals

            # Store in hass.data
            self._hass.data[DOMAIN][entry.entry_id]["battery_health"] = battery_health_data

            # Persist to storage
            store = self._hass.data[DOMAIN][entry.entry_id].get("store")
            if store:
                stored_data = await store.async_load() or {}
                stored_data["battery_health"] = battery_health_data
                await store.async_save(stored_data)
                _LOGGER.debug("Battery health persisted to storage")

            # Notify sensor via dispatcher
            from homeassistant.helpers.dispatcher import async_dispatcher_send
            async_dispatcher_send(
                self._hass,
                f"{DOMAIN}_battery_health_update_{entry.entry_id}",
                battery_health_data,
            )

            return web.json_response({
                "success": True,
                "message": f"Battery health synced: {health_percent}% health",
                "data": battery_health_data,
            })

        except Exception as e:
            _LOGGER.error(f"Error processing battery health scan: {e}", exc_info=True)
            return web.json_response(
                {"success": False, "error": str(e)},
                status=500
            )


class InverterStatusView(HomeAssistantView):
    """HTTP view to get AC-coupled inverter status for mobile app."""

    url = "/api/power_sync/inverter_status"
    name = "api:power_sync:inverter_status"
    requires_auth = True

    def __init__(self, hass: HomeAssistant):
        """Initialize the view."""
        self._hass = hass

    async def get(self, request: web.Request) -> web.Response:
        """Handle GET request for inverter status."""
        _LOGGER.info("☀️ Inverter status HTTP request")

        # Find the power_sync entry
        entry = None
        for config_entry in self._hass.config_entries.async_entries(DOMAIN):
            entry = config_entry
            break

        if not entry:
            return web.json_response(
                {"success": False, "error": "PowerSync not configured"},
                status=503
            )

        # Check if inverter curtailment is enabled
        inverter_enabled = entry.options.get(
            CONF_AC_INVERTER_CURTAILMENT_ENABLED,
            entry.data.get(CONF_AC_INVERTER_CURTAILMENT_ENABLED, False)
        )

        if not inverter_enabled:
            return web.json_response({
                "success": True,
                "enabled": False,
                "message": "Inverter curtailment not enabled"
            })

        # Get inverter configuration
        inverter_brand = entry.options.get(
            CONF_INVERTER_BRAND,
            entry.data.get(CONF_INVERTER_BRAND, "sungrow")
        )
        inverter_host = entry.options.get(
            CONF_INVERTER_HOST,
            entry.data.get(CONF_INVERTER_HOST, "")
        )
        inverter_port = entry.options.get(
            CONF_INVERTER_PORT,
            entry.data.get(CONF_INVERTER_PORT, DEFAULT_INVERTER_PORT)
        )
        inverter_slave_id = entry.options.get(
            CONF_INVERTER_SLAVE_ID,
            entry.data.get(CONF_INVERTER_SLAVE_ID, DEFAULT_INVERTER_SLAVE_ID)
        )
        inverter_model = entry.options.get(
            CONF_INVERTER_MODEL,
            entry.data.get(CONF_INVERTER_MODEL)
        )
        inverter_token = entry.options.get(
            CONF_INVERTER_TOKEN,
            entry.data.get(CONF_INVERTER_TOKEN)
        )
        fronius_load_following = entry.options.get(
            CONF_FRONIUS_LOAD_FOLLOWING,
            entry.data.get(CONF_FRONIUS_LOAD_FOLLOWING, False)
        )
        inverter_rated_power_w = entry.options.get(
            CONF_INVERTER_RATED_POWER_W,
            entry.data.get(CONF_INVERTER_RATED_POWER_W),
        )
        # Enphase Enlighten credentials for automatic JWT token refresh
        enphase_username = entry.options.get(
            CONF_ENPHASE_USERNAME,
            entry.data.get(CONF_ENPHASE_USERNAME)
        )
        enphase_password = entry.options.get(
            CONF_ENPHASE_PASSWORD,
            entry.data.get(CONF_ENPHASE_PASSWORD)
        )
        enphase_serial = entry.options.get(
            CONF_ENPHASE_SERIAL,
            entry.data.get(CONF_ENPHASE_SERIAL)
        )
        enphase_normal_profile = entry.options.get(
            CONF_ENPHASE_NORMAL_PROFILE,
            entry.data.get(CONF_ENPHASE_NORMAL_PROFILE)
        )
        enphase_zero_export_profile = entry.options.get(
            CONF_ENPHASE_ZERO_EXPORT_PROFILE,
            entry.data.get(CONF_ENPHASE_ZERO_EXPORT_PROFILE)
        )
        enphase_is_installer = entry.options.get(
            CONF_ENPHASE_IS_INSTALLER,
            entry.data.get(CONF_ENPHASE_IS_INSTALLER, False)
        )

        if not inverter_host:
            return web.json_response({
                "success": True,
                "enabled": True,
                "error": "Inverter not configured (no host)"
            })

        controller = None
        try:
            controller = get_inverter_controller(
                brand=inverter_brand,
                host=inverter_host,
                port=inverter_port,
                slave_id=inverter_slave_id,
                model=inverter_model,
                token=inverter_token,
                load_following=fronius_load_following,
                enphase_username=enphase_username,
                enphase_password=enphase_password,
                enphase_serial=enphase_serial,
                enphase_normal_profile=enphase_normal_profile,
                enphase_zero_export_profile=enphase_zero_export_profile,
                enphase_is_installer=enphase_is_installer,
                max_export_limit_kw=entry.data.get(CONF_SIGENERGY_EXPORT_LIMIT_KW),
                rated_power_w=inverter_rated_power_w,
                hass=self._hass,
            )

            if not controller:
                return web.json_response({
                    "success": False,
                    "enabled": True,
                    "error": f"Unsupported inverter brand: {inverter_brand}"
                })

            # Get status from controller
            state = await controller.get_status()

            # Convert state to dict
            state_dict = state.to_dict()

            # Use tracked inverter_last_state as source of truth for is_curtailed
            # This fixes Fronius simple mode where power_limit_enabled is False
            # but the inverter is actually curtailed using soft export limit
            entry_data = self._hass.data.get(DOMAIN, {}).get(entry.entry_id, {})
            inverter_last_state = entry_data.get("inverter_last_state")
            if inverter_last_state == "curtailed":
                state_dict["is_curtailed"] = True
                if state_dict.get("status") == "online":
                    state_dict["status"] = "curtailed"
            elif inverter_last_state in ("normal", "running"):
                state_dict["is_curtailed"] = False

            # Check if it's nighttime for sleep detection
            is_night = False
            try:
                sun_state = self._hass.states.get("sun.sun")
                if sun_state:
                    is_night = sun_state.state == "below_horizon"
                else:
                    # Fallback to hour-based check (6pm-6am) — use HA tz, not container UTC
                    local_hour = dt_util.now().hour
                    is_night = local_hour >= 18 or local_hour < 6
            except Exception:
                pass

            # Apply sleep detection at night if:
            # - Status is offline/error, OR
            # - Power output is very low (< 100W, e.g. Sungrow PID recovery mode)
            if is_night:
                power_output = state_dict.get('power_output_w', 0) or 0
                status = state_dict.get('status')
                if status in ('offline', 'error') or power_output < 100:
                    state_dict['status'] = 'sleep'
                    state_dict['error_message'] = 'Inverter in sleep mode (night)'

            result = {
                "success": True,
                "enabled": True,
                "brand": inverter_brand,
                "model": inverter_model,
                "host": inverter_host,
                **state_dict
            }

            _LOGGER.info(f"✅ Inverter status: {state_dict.get('status')}, curtailed: {state_dict.get('is_curtailed')}")
            return web.json_response(result)

        except Exception as e:
            _LOGGER.error(f"Error getting inverter status: {e}", exc_info=True)
            # Determine if it's likely nighttime (inverter sleep) vs actual offline
            # Use sun.sun entity if available for accurate sunrise/sunset
            is_night = False
            try:
                sun_state = self._hass.states.get("sun.sun")
                if sun_state:
                    is_night = sun_state.state == "below_horizon"
                else:
                    # Fallback to hour-based check (6pm-6am) — use HA tz, not container UTC
                    local_hour = dt_util.now().hour
                    is_night = local_hour >= 18 or local_hour < 6
            except Exception:
                pass

            status = "sleep" if is_night else "offline"
            description = "Inverter in sleep mode (night)" if is_night else "Cannot reach inverter"

            return web.json_response({
                "success": True,
                "enabled": True,
                "status": status,
                "is_curtailed": False,
                "power_output_w": None,
                "power_limit_percent": None,
                "brand": inverter_brand,
                "model": inverter_model,
                "host": inverter_host,
                "error_message": description
            })
        finally:
            if controller:
                try:
                    await controller.disconnect()
                except Exception as err:
                    _LOGGER.debug("Error disconnecting inverter status controller: %s", err)


